1	package com.demo.app.infrastructure.encryption;
2	
3	import jakarta.annotation.PostConstruct;
4	import org.springframework.beans.factory.annotation.Value;
5	import org.springframework.stereotype.Component;
6	
7	import javax.crypto.Cipher;
8	import javax.crypto.spec.GCMParameterSpec;
9	import javax.crypto.spec.SecretKeySpec;
10	import java.security.SecureRandom;
11	import java.util.Base64;
12	import java.util.HexFormat;
13	
14	@Component
15	public class FieldEncryptor {
16	
17	    private static final String ALGORITHM = "AES/GCM/NoPadding";
18	    private static final int GCM_TAG_LENGTH = 128;
19	    private static final int IV_LENGTH = 12;
20	
21	    @Value("${app.encryption.secret}")
22	    private String hexSecret;
23	
24	    private SecretKeySpec secretKey;
25	
26	    @PostConstruct
27	    public void init() {
28	        byte[] keyBytes = HexFormat.of().parseHex(hexSecret);
29	        byte[] key = new byte[32];
30	        System.arraycopy(keyBytes, 0, key, 0, Math.min(keyBytes.length, 32));
31	        this.secretKey = new SecretKeySpec(key, "AES");
32	    }
33	
34	    public String encrypt(String plaintext) {
35	        try {
36	            byte[] iv = new byte[IV_LENGTH];
37	            new SecureRandom().nextBytes(iv);
38	
39	            Cipher cipher = Cipher.getInstance(ALGORITHM);
40	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
41	            byte[] encrypted = cipher.doFinal(plaintext.getBytes());
42	
43	            byte[] combined = new byte[iv.length + encrypted.length];
44	            System.arraycopy(iv, 0, combined, 0, iv.length);
45	            System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);
46	
47	            return Base64.getEncoder().encodeToString(combined);
48	        } catch (Exception e) {
49	            throw new RuntimeException("Encryption failed", e);
50	        }
51	    }
52	
53	    public String decrypt(String ciphertext) {
54	        try {
55	            byte[] combined = Base64.getDecoder().decode(ciphertext);
56	            byte[] iv = new byte[IV_LENGTH];
57	            System.arraycopy(combined, 0, iv, 0, IV_LENGTH);
58	
59	            Cipher cipher = Cipher.getInstance(ALGORITHM);
60	            cipher.init(Cipher.DECRYPT_MODE, secretKey, new GCMParameterSpec(GCM_TAG_LENGTH, iv));
61	            byte[] decrypted = cipher.doFinal(combined, IV_LENGTH, combined.length - IV_LENGTH);
62	
63	            return new String(decrypted);
64	        } catch (Exception e) {
65	            throw new RuntimeException("Decryption failed", e);
66	        }
67	    }
68	}
