1	package com.demo.app.infrastructure.encryption;
2	
3	import jakarta.persistence.AttributeConverter;
4	import jakarta.persistence.Converter;
5	
6	@Converter(autoApply = false)
7	public class EncryptedStringConverter implements AttributeConverter<String, String> {
8	
9	    private static FieldEncryptor fieldEncryptor;
10	
11	    public static void setFieldEncryptor(FieldEncryptor encryptor) {
12	        fieldEncryptor = encryptor;
13	    }
14	
15	    @Override
16	    public String convertToDatabaseColumn(String attribute) {
17	        if (attribute == null) {
18	            return null;
19	        }
20	        return fieldEncryptor.encrypt(attribute);
21	    }
22	
23	    @Override
24	    public String convertToEntityAttribute(String dbData) {
25	        if (dbData == null) {
26	            return null;
27	        }
28	        return fieldEncryptor.decrypt(dbData);
29	    }
30	}
