3	import com.demo.app.domain.exception.ConflictException;
4	import com.demo.app.domain.exception.ResourceNotFoundException;
5	import com.demo.app.domain.model.Appeal;
6	import com.demo.app.persistence.entity.AppealEntity;
7	import com.demo.app.persistence.repository.AppealRepository;
8	import lombok.RequiredArgsConstructor;
9	import org.springframework.stereotype.Service;
10	import org.springframework.transaction.annotation.Transactional;
11	
12	import com.demo.app.infrastructure.config.StatusTransitions;
13	
14	import java.time.LocalDateTime;
15	import java.util.List;
16	
17	@Service
18	@RequiredArgsConstructor
19	@Transactional
20	public class AppealService {
21	
22	    private final AppealRepository appealRepository;
23	
24	    public Appeal create(Long userId, String relatedEntityType, Long relatedEntityId, String reason) {
25	        AppealEntity entity = AppealEntity.builder()
26	                .userId(userId)
27	                .relatedEntityType(relatedEntityType)
28	                .relatedEntityId(relatedEntityId)
29	                .reason(reason)
30	                .status("SUBMITTED")
31	                .createdAt(LocalDateTime.now())
32	                .build();
33	
34	        return appealRepository.save(entity).toModel();
35	    }
36	
37	    public Appeal review(Long appealId, Long reviewerId, String status, String reviewNotes) {
38	        AppealEntity entity = appealRepository.findById(appealId)
39	                .orElseThrow(() -> new ResourceNotFoundException("Appeal", appealId));
40	
41	        StatusTransitions.validate(StatusTransitions.APPEAL, entity.getStatus(), status);
42	
43	        LocalDateTime now = LocalDateTime.now();
44	        entity.setReviewerId(reviewerId);
45	        entity.setReviewNotes(reviewNotes);
46	        entity.setStatus(status);
47	        entity.setReviewedAt(now);
48	
49	        if ("APPROVED".equals(status) || "REJECTED".equals(status)) {
50	            entity.setResolvedAt(now);
51	        }
52	
53	        return appealRepository.save(entity).toModel();
54	    }
55	
56	    @Transactional(readOnly = true)
57	    public Appeal getById(Long id) {
58	        return appealRepository.findById(id)
59	                .orElseThrow(() -> new ResourceNotFoundException("Appeal", id))
60	                .toModel();
61	    }
62	
63	    @Transactional(readOnly = true)
64	    public List<Appeal> getByUser(Long userId) {
65	        return appealRepository.findByUserId(userId).stream()
66	                .map(AppealEntity::toModel)
67	                .toList();
68	    }
69	
70	    @Transactional(readOnly = true)
71	    public List<Appeal> getPending() {
72	        return appealRepository.findByStatus("SUBMITTED").stream()
73	                .map(AppealEntity::toModel)
74	                .toList();
75	    }
76	}
