24	
25	@RestController
26	@RequestMapping("/api/appeals")
27	@RequiredArgsConstructor
28	public class AppealController {
29	
30	    private final AppealService appealService;
31	    private final UserRepository userRepository;
32	    private final AppealEvidenceRepository appealEvidenceRepository;
33	    private final com.demo.app.infrastructure.encryption.EvidenceEncryptionService evidenceEncryptionService;
34	
35	    @GetMapping
36	    @PreAuthorize("hasAnyRole('MODERATOR', 'ADMINISTRATOR')")
37	    public ResponseEntity<List<AppealDto>> getPending() {
38	        List<AppealDto> appeals = appealService.getPending().stream()
39	                .map(this::toDto)
40	                .toList();
41	        return ResponseEntity.ok(appeals);
42	    }
43	
44	    @GetMapping("/my")
45	    public ResponseEntity<List<AppealDto>> getMy() {
46	        Long userId = getCurrentUserId();
47	        List<AppealDto> appeals = appealService.getByUser(userId).stream()
48	                .map(this::toDto)
49	                .toList();
50	        return ResponseEntity.ok(appeals);
51	    }
52	
53	    @GetMapping("/{id}")
54	    public ResponseEntity<AppealDto> getById(@PathVariable Long id) {
55	        Appeal appeal = appealService.getById(id);
56	        if (!isPrivileged() && !appeal.getUserId().equals(getCurrentUserId())) {
57	            throw new OwnershipViolationException("You do not have access to this appeal");
58	        }
59	        return ResponseEntity.ok(toDto(appeal));
60	    }
61	
62	    @PostMapping
63	    @Audited(entityType = "APPEAL", action = "CREATE")
64	    public ResponseEntity<AppealDto> create(@Valid @RequestBody CreateAppealRequest request) {
65	        Long userId = getCurrentUserId();
66	        Appeal appeal = appealService.create(
67	                userId,
68	                request.relatedEntityType(),
69	                request.relatedEntityId(),
70	                request.reason()
71	        );
72	        return ResponseEntity.ok(toDto(appeal));
73	    }
74	
75	    @PostMapping("/{id}/review")
76	    @PreAuthorize("hasAnyRole('MODERATOR', 'ADMINISTRATOR')")
77	    @Audited(entityType = "APPEAL", action = "REVIEW")
78	    public ResponseEntity<AppealDto> review(@PathVariable Long id, @RequestBody ReviewAppealRequest request) {
79	        Long reviewerId = getCurrentUserId();
