84	    @PostMapping("/{id}/evidence")
85	    public ResponseEntity<?> uploadEvidence(@PathVariable Long id,
86	                                            @RequestParam("file") MultipartFile file) {
87	        // Ownership check
88	        Appeal appeal = appealService.getById(id);
89	        if (!isPrivileged() && !appeal.getUserId().equals(getCurrentUserId())) {
90	            throw new OwnershipViolationException("You do not have access to this appeal");
91	        }
92	
93	        // Validate file
94	        if (file.isEmpty()) {
95	            throw new IllegalArgumentException("File is empty");
96	        }
97	        long maxSize = 10 * 1024 * 1024; // 10 MB
98	        if (file.getSize() > maxSize) {
99	            throw new IllegalArgumentException("File exceeds maximum size of 10 MB");
100	        }
101	        String contentType = file.getContentType();
102	        if (contentType == null || !(contentType.startsWith("image/") || contentType.equals("application/pdf"))) {
103	            throw new IllegalArgumentException("Only image and PDF files are allowed");
104	        }
105	        // Deep MIME validation via magic bytes
106	        try {
107	            byte[] header = new byte[8];
108	            java.io.InputStream is = file.getInputStream();
109	            int read = is.read(header);
110	            is.close();
111	            if (read >= 4) {
112	                boolean validMagic = false;
113	                // JPEG: FF D8 FF
114	                if (header[0] == (byte)0xFF && header[1] == (byte)0xD8 && header[2] == (byte)0xFF) validMagic = true;
115	                // PNG: 89 50 4E 47
116	                if (header[0] == (byte)0x89 && header[1] == 0x50 && header[2] == 0x4E && header[3] == 0x47) validMagic = true;
117	                // GIF: 47 49 46
118	                if (header[0] == 0x47 && header[1] == 0x49 && header[2] == 0x46) validMagic = true;
119	                // PDF: 25 50 44 46
120	                if (header[0] == 0x25 && header[1] == 0x50 && header[2] == 0x44 && header[3] == 0x46) validMagic = true;
121	                // WebP: 52 49 46 46 ... 57 45 42 50
122	                if (header[0] == 0x52 && header[1] == 0x49 && header[2] == 0x46 && header[3] == 0x46 && read >= 8
123	                    && header[4] == 0x57 && header[5] == 0x45 && header[6] == 0x42 && header[7] == 0x50) validMagic = true;
124	                if (!validMagic) {
125	                    throw new IllegalArgumentException("File content does not match an allowed type (image or PDF)");
126	                }
127	            }
128	        } catch (IllegalArgumentException e) {
129	            throw e;
130	        } catch (Exception e) {
131	            throw new IllegalArgumentException("Unable to validate file content");
132	        }
133	
134	        long existingCount = appealEvidenceRepository.countByAppealId(id);
135	        if (existingCount >= 5) {
136	            throw new ConflictException("Maximum 5 evidence files per appeal");
137	        }
138	
139	        // Store file locally with sanitized filename
140	        String extension = "";
141	        String originalName = file.getOriginalFilename();
142	        if (originalName != null && originalName.contains(".")) {
143	            extension = originalName.substring(originalName.lastIndexOf('.'));
144	        }
145	        // Sanitize: only allow alphanumeric extensions
146	        extension = extension.replaceAll("[^a-zA-Z0-9.]", "");
147	        String storedPath = "uploads/appeals/" + id + "/" + java.util.UUID.randomUUID() + extension;
148	        java.io.File dest = new java.io.File(storedPath);
149	        try {
150	            evidenceEncryptionService.encryptAndWrite(file.getBytes(), dest);
151	        } catch (java.io.IOException e) {
152	            throw new RuntimeException("Failed to store file");
153	        } catch (Exception e) {
154	            throw new RuntimeException("Failed to encrypt file", e);
155	        }
156	
157	        AppealEvidenceEntity evidence = AppealEvidenceEntity.builder()
158	                .appealId(id)
159	                .originalName(file.getOriginalFilename())
160	                .storedPath(storedPath)
161	                .contentType(contentType)
162	                .fileSize(file.getSize())
163	                .uploadedAt(java.time.LocalDateTime.now())
164	                .build();
165	        appealEvidenceRepository.save(evidence);
166	
167	        return ResponseEntity.ok(java.util.Map.of(
168	                "id", evidence.getId(),
169	                "originalName", evidence.getOriginalName(),
170	                "contentType", evidence.getContentType(),
171	                "fileSize", evidence.getFileSize()));
172	    }
173	
174	    @GetMapping("/{id}/evidence")
175	    public ResponseEntity<?> getEvidence(@PathVariable Long id) {
176	        Appeal appeal = appealService.getById(id);
177	        if (!isPrivileged() && !appeal.getUserId().equals(getCurrentUserId())) {
178	            throw new OwnershipViolationException("You do not have access to this appeal");
179	        }
180	        List<Map<String, Object>> sanitized = appealEvidenceRepository.findByAppealId(id).stream()
181	                .map(e -> {
182	                    Map<String, Object> m = new java.util.LinkedHashMap<>();
183	                    m.put("id", e.getId());
184	                    m.put("appealId", e.getAppealId());
185	                    m.put("originalName", e.getOriginalName());
186	                    m.put("contentType", e.getContentType());
187	                    m.put("fileSize", e.getFileSize());
188	                    m.put("uploadedAt", e.getUploadedAt());
189	                    return m;
190	                })
191	                .toList();
192	        return ResponseEntity.ok(sanitized);
193	    }
194	
195	    private boolean isPrivileged() {
196	        var auth = SecurityContextHolder.getContext().getAuthentication();
197	        return auth.getAuthorities().stream().anyMatch(a ->
198	                a.getAuthority().equals("ROLE_ADMINISTRATOR") ||
199	                a.getAuthority().equals("ROLE_MODERATOR"));
200	    }
201	
202	    private Long getCurrentUserId() {
203	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
204	        return userRepository.findByUsername(username)
205	                .orElseThrow(() -> new RuntimeException("User not found: " + username))
206	                .getId();
207	    }
208	
209	    private AppealDto toDto(Appeal a) {
210	        return new AppealDto(
211	                a.getId(),
212	                a.getUserId(),
213	                a.getRelatedEntityType(),
214	                a.getRelatedEntityId(),
215	                a.getReason(),
216	                a.getStatus(),
217	                a.getReviewerId(),
218	                a.getReviewNotes(),
219	                a.getCreatedAt(),
220	                a.getReviewedAt(),
221	                a.getResolvedAt()
222	        );
223	    }
224	}
