1	package com.demo.app.infrastructure.encryption;
2	
3	import org.slf4j.Logger;
4	import org.slf4j.LoggerFactory;
5	import org.springframework.beans.factory.annotation.Value;
6	import org.springframework.stereotype.Service;
7	
8	import javax.crypto.Cipher;
9	import javax.crypto.spec.GCMParameterSpec;
10	import javax.crypto.spec.SecretKeySpec;
11	import java.io.*;
12	import java.security.SecureRandom;
13	import java.time.LocalDateTime;
14	import java.util.HexFormat;
15	
16	/**
17	 * Manages at-rest encryption for appeal evidence files.
18	 * Supports key derivation from the application encryption secret,
19	 * with a versioned key prefix for future rotation support.
20	 */
21	@Service
22	public class EvidenceEncryptionService {
23	
24	    private static final Logger log = LoggerFactory.getLogger(EvidenceEncryptionService.class);
25	    private static final String ALGORITHM = "AES/GCM/NoPadding";
26	    private static final int GCM_TAG_BITS = 128;
27	    private static final int IV_LENGTH = 12;
28	    private static final byte KEY_VERSION = 0x01;
29	
30	    private final SecretKeySpec aesKey;
31	
32	    public EvidenceEncryptionService(@Value("${app.encryption.secret}") String hexSecret) {
33	        byte[] keyBytes = HexFormat.of().parseHex(hexSecret.substring(0, 64));
34	        this.aesKey = new SecretKeySpec(keyBytes, "AES");
35	    }
36	
37	    /**
38	     * Encrypts file content and writes to destination with versioned header.
39	     * Format: [1-byte key version][12-byte IV][encrypted content]
40	     */
41	    public void encryptAndWrite(byte[] plaintext, File destination) throws Exception {
42	        byte[] iv = new byte[IV_LENGTH];
43	        new SecureRandom().nextBytes(iv);
44	
45	        Cipher cipher = Cipher.getInstance(ALGORITHM);
46	        cipher.init(Cipher.ENCRYPT_MODE, aesKey, new GCMParameterSpec(GCM_TAG_BITS, iv));
47	        byte[] encrypted = cipher.doFinal(plaintext);
48	
49	        destination.getParentFile().mkdirs();
50	        try (OutputStream out = new FileOutputStream(destination)) {
51	            out.write(KEY_VERSION);
52	            out.write(iv);
53	            out.write(encrypted);
54	        }
55	    }
56	
57	    /**
58	     * Returns the current key version for rotation tracking.
59	     */
60	    public byte getCurrentKeyVersion() {
61	        return KEY_VERSION;
62	    }
63	
64	    /**
65	     * Securely deletes a file by overwriting with random bytes before deletion.
66	     * Provides best-effort secure deletion for local filesystem storage.
67	     */
68	    public void secureDelete(File file) {
69	        if (!file.exists()) return;
70	        try {
71	            long length = file.length();
72	            try (RandomAccessFile raf = new RandomAccessFile(file, "rw")) {
73	                byte[] noise = new byte[(int) Math.min(length, 8192)];
74	                new SecureRandom().nextBytes(noise);
75	                raf.seek(0);
76	                long written = 0;
77	                while (written < length) {
78	                    int chunk = (int) Math.min(noise.length, length - written);
79	                    raf.write(noise, 0, chunk);
80	                    written += chunk;
81	                }
82	            }
83	            if (!file.delete()) {
84	                log.warn("Failed to delete evidence file: {}", file.getAbsolutePath());
85	            }
86	        } catch (IOException e) {
87	            log.error("Secure deletion failed for: {}", file.getAbsolutePath(), e);
88	        }
89	    }
90	}
