20	
21	@Service
22	@RequiredArgsConstructor
23	@Transactional
24	public class IncidentService {
25	
26	    private final IncidentRepository incidentRepository;
27	    private final IncidentCommentRepository incidentCommentRepository;
28	    private final UserRepository userRepository;
29	
30	    @Value("${app.incident.ack-sla-minutes:15}")
31	    private int ackSlaMinutes;
32	
33	    @Value("${app.incident.resolve-sla-hours:24}")
34	    private int resolveSlaHours;
35	
36	    private static final List<String> STATUS_ORDER = List.of(
37	            "OPEN", "ACKNOWLEDGED", "IN_PROGRESS", "RESOLVED", "CLOSED"
38	    );
39	
40	    public Incident create(Long reporterId, String incidentType, String severity, String title, String description,
41	                           String address, String crossStreet) {
42	        LocalDateTime now = LocalDateTime.now();
43	
44	        int ackMinutes = ackSlaMinutes;
45	        int resolveHours = resolveSlaHours;
46	
47	        if ("EMERGENCY".equals(severity)) {
48	            ackMinutes = ackMinutes / 2;
49	            resolveHours = resolveHours / 2;
50	        }
51	
52	        IncidentEntity entity = IncidentEntity.builder()
53	                .reporterId(reporterId)
54	                .incidentType(incidentType)
55	                .severity(severity)
56	                .title(title)
57	                .description(description)
58	                .address(address)
59	                .crossStreet(crossStreet)
60	                .status("OPEN")
61	                .escalationLevel(0)
62	                .slaAckDeadline(now.plusMinutes(ackMinutes))
63	                .slaResolveDeadline(now.plusHours(resolveHours))
64	                .createdAt(now)
65	                .updatedAt(now)
66	                .build();
67	
68	        return incidentRepository.save(entity).toModel();
69	    }
70	
71	    public Incident acknowledge(Long incidentId, Long assigneeId) {
72	        IncidentEntity entity = incidentRepository.findById(incidentId)
73	                .orElseThrow(() -> new ResourceNotFoundException("Incident", incidentId));
74	
75	        int currentIndex = STATUS_ORDER.indexOf(entity.getStatus());
76	        int ackIndex = STATUS_ORDER.indexOf("ACKNOWLEDGED");
77	        if (currentIndex >= ackIndex) {
78	            return entity.toModel();
79	        }
80	
81	        LocalDateTime now = LocalDateTime.now();
82	        entity.setStatus("ACKNOWLEDGED");
83	        entity.setAssigneeId(assigneeId);
84	        entity.setAcknowledgedAt(now);
85	        entity.setUpdatedAt(now);
86	
87	        return incidentRepository.save(entity).toModel();
88	    }
89	
90	    public Incident updateStatus(Long incidentId, String newStatus, String closureCode) {
91	        IncidentEntity entity = incidentRepository.findById(incidentId)
92	                .orElseThrow(() -> new ResourceNotFoundException("Incident", incidentId));
93	
94	        StatusTransitions.validate(StatusTransitions.INCIDENT, entity.getStatus(), newStatus);
95	
96	        if ("RESOLVED".equals(newStatus) && (closureCode == null || closureCode.isBlank())) {
97	            throw new IllegalArgumentException("Closure code is required when resolving an incident");
98	        }
99	
100	        LocalDateTime now = LocalDateTime.now();
101	        entity.setStatus(newStatus);
102	        entity.setUpdatedAt(now);
103	
104	        if ("RESOLVED".equals(newStatus)) {
105	            entity.setResolvedAt(now);
106	            entity.setClosureCode(closureCode);
107	        }
108	
109	        return incidentRepository.save(entity).toModel();
110	    }
