1	package com.demo.app.application.service;
2	
3	import com.demo.app.persistence.entity.RiskEventEntity;
4	import com.demo.app.persistence.entity.RiskScoreEntity;
5	import com.demo.app.persistence.entity.UserEntity;
6	import com.demo.app.persistence.repository.AppealRepository;
7	import com.demo.app.persistence.repository.IncidentRepository;
8	import com.demo.app.persistence.repository.LoginAttemptRepository;
9	import com.demo.app.persistence.repository.RiskEventRepository;
10	import com.demo.app.persistence.repository.RiskScoreRepository;
11	import com.demo.app.persistence.repository.UserRepository;
12	import com.fasterxml.jackson.databind.ObjectMapper;
13	import lombok.RequiredArgsConstructor;
14	import org.slf4j.Logger;
15	import org.slf4j.LoggerFactory;
16	import org.springframework.stereotype.Service;
17	import org.springframework.transaction.annotation.Transactional;
18	
19	import java.time.LocalDateTime;
20	import java.util.HashMap;
21	import java.util.List;
22	import java.util.Map;
23	
24	@Service
25	@RequiredArgsConstructor
26	public class RiskAnalyticsService {
27	
28	    private static final Logger log = LoggerFactory.getLogger(RiskAnalyticsService.class);
29	
30	    private final RiskEventRepository riskEventRepository;
31	    private final RiskScoreRepository riskScoreRepository;
32	    private final LoginAttemptRepository loginAttemptRepository;
33	    private final IncidentRepository incidentRepository;
34	    private final AppealRepository appealRepository;
35	    private final UserRepository userRepository;
36	    private final ObjectMapper objectMapper;
37	
38	    @Transactional
39	    public RiskEventEntity recordEvent(Long userId, String eventType, String severity, Map<String, Object> details) {
40	        String detailsJson;
41	        try {
42	            detailsJson = details != null ? objectMapper.writeValueAsString(details) : null;
43	        } catch (Exception e) {
44	            detailsJson = null;
45	        }
46	
47	        RiskEventEntity event = RiskEventEntity.builder()
48	                .userId(userId)
49	                .eventType(eventType)
50	                .severity(severity)
51	                .details(detailsJson)
52	                .createdAt(LocalDateTime.now())
53	                .build();
54	
55	        return riskEventRepository.save(event);
56	    }
57	
58	    @Transactional
59	    public RiskScoreEntity computeScore(Long userId) {
60	        LocalDateTime thirtyDaysAgo = LocalDateTime.now().minusDays(30);
61	        List<RiskEventEntity> recentEvents = riskEventRepository.findByUserIdAndCreatedAtAfter(userId, thirtyDaysAgo);
62	
63	        double score = 0.0;
64	        Map<String, Object> factors = new HashMap<>();
65	
66	        // Per-user scoped: only incidents reported by this user
67	        List<com.demo.app.persistence.entity.IncidentEntity> userRecentIncidents =
68	            incidentRepository.findByReporterId(userId).stream()
69	                .filter(i -> i.getCreatedAt() != null && i.getCreatedAt().isAfter(thirtyDaysAgo))
70	                .toList();
71	
72	        // Staff-flagged exceptions (escalated incidents)
73	        long escalatedIncidents = userRecentIncidents.stream()
74	                .filter(i -> i.getEscalationLevel() > 0)
75	                .count();
76	        factors.put("escalated_incidents_30d", escalatedIncidents);
77	        score += escalatedIncidents * 15.0;
78	
79	        // Seller-specific: incidents assigned to this user (flagged by moderators)
80	        long assignedIncidents = incidentRepository.findByAssigneeId(userId).stream()
81	                .filter(i -> i.getCreatedAt() != null && i.getCreatedAt().isAfter(thirtyDaysAgo))
82	                .count();
83	        factors.put("assigned_incidents_30d", assignedIncidents);
84	        score += assignedIncidents * 12.0;
85	
86	        // Repeat incident signal: if same user has >2 incidents in 30 days
87	        long repeatSignal = userRecentIncidents.size() > 2 ? userRecentIncidents.size() - 2 : 0;
88	        factors.put("repeat_incident_penalty", repeatSignal);
89	        score += repeatSignal * 8.0;
90	
91	        // Rejected appeals (staff exceptions denied)
92	        long rejectedAppeals = appealRepository.findByUserId(userId).stream()
93	                .filter(a -> "REJECTED".equals(a.getStatus()))
94	                .filter(a -> a.getResolvedAt() != null && a.getResolvedAt().isAfter(thirtyDaysAgo))
95	                .count();
96	        factors.put("rejected_appeals_30d", rejectedAppeals);
97	        score += rejectedAppeals * 10.0;
98	
99	        // Failed logins (account compromise risk)
100	        UserEntity user = userRepository.findById(userId).orElse(null);
101	        long failedLogins = 0;
102	        if (user != null) {
103	            failedLogins = loginAttemptRepository.countRecentFailed(user.getUsername(), thirtyDaysAgo);
104	        }
105	        factors.put("failed_logins_30d", failedLogins);
106	        score += failedLogins * 3.0;
107	
108	        // High severity risk events
109	        long highSeverityEvents = recentEvents.stream()
110	                .filter(e -> "HIGH".equals(e.getSeverity()) || "CRITICAL".equals(e.getSeverity()))
111	                .count();
112	        factors.put("high_severity_events_30d", highSeverityEvents);
113	        score += highSeverityEvents * 12.0;
114	
115	        // Anomaly categories: specific operational risk signals
116	        long missedPickupCheckins = recentEvents.stream()
117	                .filter(e -> "MISSED_PICKUP_CHECKIN".equals(e.getEventType()))
118	                .count();
119	        factors.put("missed_pickup_checkins_30d", missedPickupCheckins);
120	        score += missedPickupCheckins * 10.0;
121	
122	        long buddyPunchingEvents = recentEvents.stream()
123	                .filter(e -> "BUDDY_PUNCHING".equals(e.getEventType()))
124	                .count();
125	        factors.put("buddy_punching_30d", buddyPunchingEvents);
126	        score += buddyPunchingEvents * 20.0;
127	
128	        long misidentificationEvents = recentEvents.stream()
129	                .filter(e -> "MISIDENTIFICATION".equals(e.getEventType()))
130	                .count();
131	        factors.put("misidentification_30d", misidentificationEvents);
132	        score += misidentificationEvents * 15.0;
133	
134	        score = Math.min(score, 100.0);
135	
136	        String factorsJson;
137	        try {
138	            factorsJson = objectMapper.writeValueAsString(factors);
139	        } catch (Exception e) {
140	            factorsJson = "{}";
141	        }
142	
143	        RiskScoreEntity riskScore = riskScoreRepository.findByUserId(userId)
144	                .orElse(RiskScoreEntity.builder().userId(userId).build());
145	
146	        riskScore.setScore(score);
147	        riskScore.setFactors(factorsJson);
148	        riskScore.setComputedAt(LocalDateTime.now());
149	        riskScore.setSellerComplaintCount((int) escalatedIncidents);
150	        riskScore.setOpenIncidentCount((int) assignedIncidents);
151	        riskScore.setAppealRejectionCount((int) rejectedAppeals);
152	
153	        return riskScoreRepository.save(riskScore);
154	    }
155	
156	    public RiskScoreEntity getScore(Long userId) {
157	        return riskScoreRepository.findByUserId(userId).orElse(null);
158	    }
159	
160	    public List<RiskScoreEntity> getHighRiskUsers(double threshold) {
161	        return riskScoreRepository.findByScoreGreaterThanOrderByScoreDesc(threshold);
162	    }
163	
164	    public List<RiskEventEntity> getEventsByUser(Long userId) {
165	        return riskEventRepository.findByUserIdOrderByCreatedAtDesc(userId);
166	    }
167	}
