1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.enums.Role;
4	import com.demo.app.domain.model.User;
5	import com.demo.app.infrastructure.ratelimit.LoginAttemptService;
6	import com.demo.app.persistence.entity.UserEntity;
7	import com.demo.app.persistence.repository.UserRepository;
8	import com.demo.app.security.JwtService;
9	import lombok.RequiredArgsConstructor;
10	import org.springframework.security.authentication.AuthenticationManager;
11	import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
12	import org.springframework.security.core.AuthenticationException;
13	import org.springframework.security.crypto.password.PasswordEncoder;
14	import org.springframework.stereotype.Service;
15	import org.springframework.transaction.annotation.Transactional;
16	import org.springframework.web.context.request.RequestContextHolder;
17	import org.springframework.web.context.request.ServletRequestAttributes;
18	
19	import java.time.LocalDateTime;
20	
21	@Service
22	@RequiredArgsConstructor
23	public class AuthService {
24	
25	    private final UserRepository userRepository;
26	    private final PasswordEncoder passwordEncoder;
27	    private final JwtService jwtService;
28	    private final AuthenticationManager authenticationManager;
29	    private final LoginAttemptService loginAttemptService;
30	
31	    public String login(String username, String password) {
32	        if (loginAttemptService.isLockedOut(username)) {
33	            throw new RuntimeException("Account temporarily locked due to too many failed login attempts. Try again in 15 minutes.");
34	        }
35	
36	        String ip = resolveIp();
37	
38	        try {
39	            authenticationManager.authenticate(
40	                    new UsernamePasswordAuthenticationToken(username, password)
41	            );
42	        } catch (AuthenticationException e) {
43	            loginAttemptService.recordAttempt(username, ip, false);
44	            throw e;
45	        }
46	
47	        loginAttemptService.recordAttempt(username, ip, true);
48	        UserEntity user = userRepository.findByUsername(username)
49	                .orElseThrow(() -> new RuntimeException("User not found: " + username));
50	        return jwtService.generateToken(user.getUsername(), user.getRole().name());
51	    }
52	
53	    private String resolveIp() {
54	        try {
55	            ServletRequestAttributes attrs = (ServletRequestAttributes) RequestContextHolder.getRequestAttributes();
56	            return attrs != null ? attrs.getRequest().getRemoteAddr() : "unknown";
57	        } catch (Exception e) {
58	            return "unknown";
59	        }
60	    }
61	
62	    @Transactional
63	    public User register(String username, String email, String password, String displayName) {
64	        if (userRepository.existsByUsername(username)) {
65	            throw new RuntimeException("Username already taken: " + username);
66	        }
67	        if (userRepository.existsByEmail(email)) {
68	            throw new RuntimeException("Email already in use: " + email);
69	        }
70	
71	        UserEntity entity = UserEntity.builder()
72	                .username(username)
73	                .email(email)
74	                .passwordHash(passwordEncoder.encode(password))
75	                .displayName(displayName)
76	                .role(Role.MEMBER)
77	                .enabled(true)
78	                .createdAt(LocalDateTime.now())
79	                .updatedAt(LocalDateTime.now())
80	                .build();
81	
82	        return userRepository.save(entity).toModel();
83	    }
84	}
