3	import org.junit.jupiter.api.BeforeEach;
4	import org.junit.jupiter.api.DisplayName;
5	import org.junit.jupiter.api.Test;
6	
7	import java.lang.reflect.Field;
8	import java.util.Base64;
9	
10	import static org.junit.jupiter.api.Assertions.*;
11	
12	@DisplayName("FieldEncryptor - AES-GCM encryption and decryption")
13	class FieldEncryptorTest {
14	
15	    private FieldEncryptor fieldEncryptor;
16	
17	    @BeforeEach
18	    void setUp() throws Exception {
19	        fieldEncryptor = new FieldEncryptor();
20	
21	        // Set the hexSecret via reflection since it is injected by @Value
22	        Field hexSecretField = FieldEncryptor.class.getDeclaredField("hexSecret");
23	        hexSecretField.setAccessible(true);
24	        hexSecretField.set(fieldEncryptor, "c9f2e8d1a7b6c5d4e3f2a1b0c9d8e7f6a5b4c3d2e1f0a9b8c7d6e5f4a3b2c1d0");
25	
26	        // Trigger @PostConstruct manually
27	        fieldEncryptor.init();
28	    }
29	
30	    @Test
31	    @DisplayName("Encrypt and decrypt round-trip preserves original plaintext")
32	    void testEncryptAndDecrypt_roundTrip() {
33	        String plaintext = "Hello World";
34	
35	        String encrypted = fieldEncryptor.encrypt(plaintext);
36	        String decrypted = fieldEncryptor.decrypt(encrypted);
37	
38	        assertEquals(plaintext, decrypted);
39	    }
40	
41	    @Test
42	    @DisplayName("Encrypt produces valid Base64 output")
43	    void testEncrypt_producesBase64Output() {
44	        String encrypted = fieldEncryptor.encrypt("test data");
45	
46	        assertNotNull(encrypted);
47	        assertDoesNotThrow(() -> Base64.getDecoder().decode(encrypted),
48	                "Encrypted output should be valid Base64");
49	    }
50	
51	    @Test
52	    @DisplayName("Encrypt same string twice produces different ciphertexts due to random IVs")
53	    void testEncrypt_differentIVs_differentCiphertexts() {
54	        String plaintext = "identical input";
55	
56	        String encrypted1 = fieldEncryptor.encrypt(plaintext);
57	        String encrypted2 = fieldEncryptor.encrypt(plaintext);
58	
59	        assertNotEquals(encrypted1, encrypted2,
60	                "Two encryptions of the same plaintext should differ due to random IVs");
61	    }
62	
63	    @Test
64	    @DisplayName("Decrypt with invalid input throws RuntimeException")
65	    void testDecrypt_invalidInput_throws() {
66	        assertThrows(RuntimeException.class, () -> fieldEncryptor.decrypt("not-valid-base64!!!"));
67	    }
68	
69	    @Test
70	    @DisplayName("Decrypt with corrupted ciphertext throws RuntimeException")
71	    void testDecrypt_corruptedCiphertext_throws() {
72	        String encrypted = fieldEncryptor.encrypt("some data");
73	        // Corrupt the ciphertext by changing characters in the middle
74	        String corrupted = encrypted.substring(0, 10) + "AAAA" + encrypted.substring(14);
75	
76	        assertThrows(RuntimeException.class, () -> fieldEncryptor.decrypt(corrupted));
77	    }
78	
79	    @Test
80	    @DisplayName("Encrypt and decrypt phone number round-trip")
81	    void testEncryptPhoneNumber_roundTrip() {
82	        String phone = "+1234567890";
83	
84	        String encrypted = fieldEncryptor.encrypt(phone);
85	        String decrypted = fieldEncryptor.decrypt(encrypted);
86	
87	        assertEquals(phone, decrypted);
88	    }
89	}
