131	    public List<Incident> getByReporter(Long reporterId) {
132	        return incidentRepository.findByReporterId(reporterId).stream()
133	                .map(IncidentEntity::toModel)
134	                .toList();
135	    }
136	
137	    @Transactional(readOnly = true)
138	    public List<Incident> getAll() {
139	        return incidentRepository.findAll().stream()
140	                .map(IncidentEntity::toModel)
141	                .toList();
142	    }
143	
144	    @Transactional(readOnly = true)
145	    public List<IncidentComment> getComments(Long incidentId) {
146	        return incidentCommentRepository.findByIncidentIdOrderByCreatedAtAsc(incidentId).stream()
147	                .map(IncidentCommentEntity::toModel)
148	                .toList();
149	    }
150	}
