2	
3	import com.demo.app.domain.exception.ConflictException;
4	import com.demo.app.domain.exception.InsufficientStockException;
5	import com.demo.app.domain.exception.OwnershipViolationException;
6	import com.demo.app.domain.exception.ResourceNotFoundException;
7	import org.springframework.http.HttpStatus;
8	import org.springframework.http.ResponseEntity;
9	import org.springframework.security.access.AccessDeniedException;
10	import org.springframework.security.core.AuthenticationException;
11	import org.springframework.web.bind.MethodArgumentNotValidException;
12	import org.springframework.web.bind.annotation.ExceptionHandler;
13	import org.springframework.web.bind.annotation.RestControllerAdvice;
14	
15	import java.util.HashMap;
16	import java.util.Map;
17	
18	@RestControllerAdvice
19	public class GlobalExceptionHandler {
20	
21	    @ExceptionHandler(ResourceNotFoundException.class)
22	    public ResponseEntity<Map<String, Object>> handleNotFound(ResourceNotFoundException ex) {
23	        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(Map.of("error", ex.getMessage()));
24	    }
25	
26	    @ExceptionHandler(ConflictException.class)
27	    public ResponseEntity<Map<String, Object>> handleConflict(ConflictException ex) {
28	        return ResponseEntity.status(HttpStatus.CONFLICT).body(Map.of("error", ex.getMessage()));
29	    }
30	
31	    @ExceptionHandler(OwnershipViolationException.class)
32	    public ResponseEntity<Map<String, Object>> handleOwnership(OwnershipViolationException ex) {
33	        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(Map.of("error", ex.getMessage()));
34	    }
35	
36	    @ExceptionHandler(InsufficientStockException.class)
37	    public ResponseEntity<Map<String, Object>> handleInsufficientStock(InsufficientStockException ex) {
38	        return ResponseEntity.status(HttpStatus.CONFLICT).body(Map.of("error", ex.getMessage()));
39	    }
40	
41	    @ExceptionHandler(IllegalStateException.class)
42	    public ResponseEntity<Map<String, Object>> handleIllegalState(IllegalStateException ex) {
43	        return ResponseEntity.status(HttpStatus.CONFLICT).body(Map.of("error", ex.getMessage()));
44	    }
45	
46	    @ExceptionHandler(AccessDeniedException.class)
47	    public ResponseEntity<Map<String, Object>> handleAccessDenied(AccessDeniedException ex) {
48	        return ResponseEntity.status(HttpStatus.FORBIDDEN).body(Map.of("error", "Access denied"));
49	    }
50	
51	    @ExceptionHandler(AuthenticationException.class)
52	    public ResponseEntity<Map<String, Object>> handleAuth(AuthenticationException ex) {
53	        return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(Map.of("error", "Authentication failed"));
54	    }
55	
56	    @ExceptionHandler(MethodArgumentNotValidException.class)
57	    public ResponseEntity<Map<String, Object>> handleValidation(MethodArgumentNotValidException ex) {
58	        Map<String, String> fieldErrors = new HashMap<>();
59	        ex.getBindingResult().getFieldErrors().forEach(err ->
60	                fieldErrors.put(err.getField(), err.getDefaultMessage()));
61	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(Map.of("error", "Validation failed", "fields", fieldErrors));
62	    }
63	
64	    @ExceptionHandler(RuntimeException.class)
65	    public ResponseEntity<Map<String, Object>> handleRuntime(RuntimeException ex) {
66	        // Sanitize: never expose stack traces or class names
67	        String safe = "Invalid request";
68	        String msg = ex.getMessage();
69	        if (msg != null && !msg.contains("Exception") && !msg.contains("org.") && !msg.contains("com.demo")) {
70	            safe = msg;
71	        }
72	        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(Map.of("error", "BAD_REQUEST", "message", safe));
73	    }
74	
75	    @ExceptionHandler(Exception.class)
76	    public ResponseEntity<Map<String, Object>> handleGeneric(Exception ex) {
77	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(Map.of(
78	                "error", "INTERNAL_ERROR",
79	                "message", "An unexpected error occurred"
80	        ));
81	    }
82	}
