1	import React, { useEffect, useState } from 'react';
2	import { useParams } from 'react-router-dom';
3	import { useAuthStore } from '@/state/authStore';
4	import { Incident, IncidentComment } from '@/api/types';
5	import { getIncident, getIncidentComments, addIncidentComment, acknowledgeIncident, updateIncidentStatus } from '@/api/incidents';
6	
7	const IncidentDetailPage: React.FC = () => {
8	  const { id } = useParams<{ id: string }>();
9	  const user = useAuthStore((s) => s.user);
10	  const isMod = user?.role === 'MODERATOR' || user?.role === 'ADMINISTRATOR';
11	  const [incident, setIncident] = useState<Incident | null>(null);
12	  const [comments, setComments] = useState<IncidentComment[]>([]);
13	  const [newComment, setNewComment] = useState('');
14	  const [loading, setLoading] = useState(true);
15	
16	  const load = async () => {
17	    if (!id) return;
18	    setLoading(true);
19	    try {
20	      const [inc, cmts] = await Promise.all([getIncident(+id), getIncidentComments(+id)]);
21	      setIncident(inc);
22	      setComments(cmts);
23	    } catch {}
24	    setLoading(false);
25	  };
26	
27	  useEffect(() => { load(); }, [id]);
28	
29	  const handleAcknowledge = async () => {
30	    if (!id) return;
31	    await acknowledgeIncident(+id);
32	    load();
33	  };
34	
35	  const handleStatusChange = async (status: string) => {
36	    if (!id) return;
37	    await updateIncidentStatus(+id, status);
38	    load();
39	  };
40	
41	  const handleComment = async (e: React.FormEvent) => {
42	    e.preventDefault();
43	    if (!id || !newComment.trim()) return;
44	    await addIncidentComment(+id, newComment);
45	    setNewComment('');
46	    load();
47	  };
48	
49	  if (loading) return <div className="page"><p className="text-muted">Loading...</p></div>;
50	  if (!incident) return <div className="page"><p className="text-muted">Incident not found.</p></div>;
51	
52	  const slaBreached = incident.status === 'OPEN' && incident.slaAckDeadline && new Date(incident.slaAckDeadline) < new Date();
53	
54	  return (
55	    <div className="page">
56	      <div className="page-header">
57	        <h1>Incident #{incident.id}: {incident.title}</h1>
58	      </div>
59	
60	      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
61	        <div>
62	          <div className="card" style={{ marginBottom: '1.5rem' }}>
63	            <div className="card-header">Details</div>
64	            <div className="card-body">
65	              <p><strong>Type:</strong> {incident.incidentType.replace(/_/g, ' ')}</p>
66	              <p><strong>Severity:</strong> <span className={incident.severity === 'HIGH' || incident.severity === 'EMERGENCY' ? 'badge badge-danger' : 'badge badge-warning'}>{incident.severity}</span></p>
67	              <p><strong>Status:</strong> <span className={incident.status === 'RESOLVED' ? 'badge badge-success' : 'badge badge-info'}>{incident.status}</span></p>
68	              {incident.escalationLevel > 0 && <p><strong>Escalation Level:</strong> <span className="badge badge-danger">L{incident.escalationLevel}</span></p>}
69	              {slaBreached && <div className="alert alert-danger" style={{ marginTop: '0.5rem' }}>SLA BREACHED - Acknowledgment overdue</div>}
70	              <hr style={{ margin: '1rem 0', border: 'none', borderTop: '1px solid var(--neutral-200)' }} />
71	              <p style={{ whiteSpace: 'pre-wrap' }}>{incident.description}</p>
72	            </div>
73	          </div>
74	
75	          <div className="card">
76	            <div className="card-header">Comments ({comments.length})</div>
77	            <div className="card-body">
78	              {comments.length === 0 && <p className="text-muted">No comments yet.</p>}
79	              {comments.map((c) => (
80	                <div key={c.id} style={{ padding: '0.75rem 0', borderBottom: '1px solid var(--neutral-200)' }}>
81	                  <div className="flex gap-sm">
82	                    <strong>User #{c.authorId}</strong>
83	                    <span className="text-muted" style={{ fontSize: '0.8rem' }}>{new Date(c.createdAt).toLocaleString()}</span>
84	                  </div>
85	                  <p style={{ marginTop: '0.25rem' }}>{c.content}</p>
86	                </div>
87	              ))}
88	              <form onSubmit={handleComment} style={{ marginTop: '1rem' }}>
89	                <textarea className="form-input" rows={3} placeholder="Add a comment..." value={newComment} onChange={(e) => setNewComment(e.target.value)} />
90	                <div className="form-actions"><button type="submit" className="btn btn-primary btn-sm">Post Comment</button></div>
91	              </form>
92	            </div>
93	          </div>
94	        </div>
95	
96	        <div>
97	          <div className="card" style={{ marginBottom: '1rem' }}>
98	            <div className="card-header">Timeline</div>
99	            <div className="card-body" style={{ fontSize: '0.85rem' }}>
100	              <p><strong>Created:</strong> {new Date(incident.createdAt).toLocaleString()}</p>
101	              {incident.acknowledgedAt && <p><strong>Acknowledged:</strong> {new Date(incident.acknowledgedAt).toLocaleString()}</p>}
102	              {incident.resolvedAt && <p><strong>Resolved:</strong> {new Date(incident.resolvedAt).toLocaleString()}</p>}
103	              {incident.slaAckDeadline && <p><strong>Ack SLA:</strong> {new Date(incident.slaAckDeadline).toLocaleString()}</p>}
104	              {incident.slaResolveDeadline && <p><strong>Resolve SLA:</strong> {new Date(incident.slaResolveDeadline).toLocaleString()}</p>}
105	            </div>
106	          </div>
107	
108	          {isMod && (
109	            <div className="card">
110	              <div className="card-header">Actions</div>
111	              <div className="card-body" style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
112	                {incident.status === 'OPEN' && (
113	                  <button className="btn btn-primary btn-block" onClick={handleAcknowledge}>Acknowledge</button>
114	                )}
115	                {incident.status === 'ACKNOWLEDGED' && (
116	                  <button className="btn btn-primary btn-block" onClick={() => handleStatusChange('IN_PROGRESS')}>Start Work</button>
117	                )}
118	                {(incident.status === 'IN_PROGRESS' || incident.status === 'ACKNOWLEDGED') && (
119	                  <button className="btn btn-primary btn-block" style={{ background: 'var(--success)' }} onClick={() => handleStatusChange('RESOLVED')}>Resolve</button>
120	                )}
121	                {incident.status === 'RESOLVED' && (
122	                  <button className="btn btn-secondary btn-block" onClick={() => handleStatusChange('CLOSED')}>Close</button>
123	                )}
124	              </div>
125	            </div>
126	          )}
127	        </div>
128	      </div>
129	    </div>
130	  );
131	};
132	
133	export default IncidentDetailPage;
134

