1	package com.demo.app.api.controller;
2	
3	import com.demo.app.api.dto.InboundRequest;
4	import com.demo.app.api.dto.InventoryItemDto;
5	import com.demo.app.api.dto.OutboundRequest;
6	import com.demo.app.api.dto.StocktakeRequest;
7	import com.demo.app.application.service.InventoryService;
8	import com.demo.app.application.service.ProductService;
9	import com.demo.app.domain.model.InventoryItem;
10	import com.demo.app.infrastructure.audit.Audited;
11	import com.demo.app.persistence.repository.UserRepository;
12	import com.demo.app.persistence.repository.WarehouseRepository;
13	import lombok.RequiredArgsConstructor;
14	import org.springframework.http.ResponseEntity;
15	import org.springframework.security.access.prepost.PreAuthorize;
16	import org.springframework.security.core.context.SecurityContextHolder;
17	import org.springframework.web.bind.annotation.*;
18	
19	import java.util.List;
20	import java.util.Map;
21	
22	@RestController
23	@RequestMapping("/api/inventory")
24	@RequiredArgsConstructor
25	public class InventoryController {
26	
27	    private final InventoryService inventoryService;
28	    private final ProductService productService;
29	    private final UserRepository userRepository;
30	    private final WarehouseRepository warehouseRepository;
31	
32	    @GetMapping("/product/{productId}")
33	    public ResponseEntity<List<InventoryItemDto>> getByProduct(@PathVariable Long productId) {
34	        // Seller scoping: sellers can only see inventory for their own products
35	        if (isSeller()) {
36	            Long currentUserId = getCurrentUserId();
37	            com.demo.app.domain.model.Product product = productService.getById(productId);
38	            if (!product.getSellerId().equals(currentUserId)) {
39	                throw new com.demo.app.domain.exception.OwnershipViolationException(
40	                        "Sellers can only view inventory for their own products");
41	            }
42	        }
43	        List<InventoryItemDto> items = inventoryService.getByProduct(productId).stream()
44	                .map(this::toDto)
45	                .toList();
46	        return ResponseEntity.ok(items);
47	    }
48	
49	    @GetMapping("/low-stock")
50	    public ResponseEntity<List<InventoryItemDto>> getLowStock() {
51	        List<InventoryItemDto> items = inventoryService.getLowStockItems().stream()
52	                .map(this::toDto)
53	                .toList();
54	        // Seller scoping: only show low-stock for seller's own products
55	        if (isSeller()) {
56	            Long currentUserId = getCurrentUserId();
57	            items = items.stream().filter(i -> {
58	                try {
59	                    com.demo.app.domain.model.Product p = productService.getById(i.productId());
60	                    return p.getSellerId().equals(currentUserId);
61	                } catch (Exception e) { return false; }
62	            }).toList();
63	        }
64	        return ResponseEntity.ok(items);
65	    }
66	
67	    @PostMapping("/adjust")
68	    @PreAuthorize("hasAnyRole('WAREHOUSE_STAFF', 'ADMINISTRATOR')")
69	    public ResponseEntity<InventoryItemDto> adjustStock(@RequestBody Map<String, Object> body) {
70	        Long inventoryItemId = ((Number) body.get("inventoryItemId")).longValue();
71	        int quantityChange = ((Number) body.get("quantityChange")).intValue();
72	        String movementType = (String) body.get("movementType");
73	        String referenceDocument = (String) body.get("referenceDocument");
74	        String notes = (String) body.get("notes");
75	
76	        Long operatorId = getCurrentUserId();
77	
78	        InventoryItem item = inventoryService.adjustStock(inventoryItemId, quantityChange, movementType,
79	                referenceDocument, operatorId, notes);
80	        return ResponseEntity.ok(toDto(item));
81	    }
82	
83	    @PostMapping("/inbound")
84	    @PreAuthorize("hasAnyRole('WAREHOUSE_STAFF', 'ADMINISTRATOR')")
85	    @Audited(entityType = "INVENTORY", action = "INBOUND")
86	    public ResponseEntity<InventoryItemDto> recordInbound(@RequestBody @jakarta.validation.Valid InboundRequest request) {
87	        Long operatorId = getCurrentUserId();
88	        InventoryItem item = inventoryService.adjustStock(
89	                request.inventoryItemId(), request.quantity(), "INBOUND",
90	                request.referenceDocument(), operatorId, request.notes());
91	        return ResponseEntity.ok(toDto(item));
92	    }
93	
94	    @PostMapping("/outbound")
95	    @PreAuthorize("hasAnyRole('WAREHOUSE_STAFF', 'ADMINISTRATOR')")
96	    @Audited(entityType = "INVENTORY", action = "OUTBOUND")
97	    public ResponseEntity<InventoryItemDto> recordOutbound(@RequestBody @jakarta.validation.Valid OutboundRequest request) {
98	        Long operatorId = getCurrentUserId();
99	        InventoryItem item = inventoryService.adjustStock(
100	                request.inventoryItemId(), -request.quantity(), "OUTBOUND",
101	                request.referenceDocument(), operatorId, request.notes());
102	        return ResponseEntity.ok(toDto(item));
103	    }
104	
105	    @PostMapping("/stocktake")
106	    @PreAuthorize("hasAnyRole('WAREHOUSE_STAFF', 'ADMINISTRATOR')")
107	    @Audited(entityType = "INVENTORY", action = "STOCKTAKE")
108	    public ResponseEntity<InventoryItemDto> recordStocktake(@RequestBody @jakarta.validation.Valid StocktakeRequest request) {
109	        Long operatorId = getCurrentUserId();
110	        // Stocktake: set absolute quantity, compute delta
111	        InventoryItem current = inventoryService.getByProductAndWarehouse(request.productId(), request.warehouseId());
112	        int delta = request.countedQuantity() - current.getQuantityOnHand();
113	        InventoryItem item = inventoryService.adjustStock(
114	                current.getId(), delta, "STOCKTAKE",
115	                request.referenceDocument(), operatorId, "Stocktake: counted=" + request.countedQuantity());
116	        return ResponseEntity.ok(toDto(item));
117	    }
118	
119	    private boolean isSeller() {
120	        var auth = SecurityContextHolder.getContext().getAuthentication();
121	        return auth.getAuthorities().stream().anyMatch(a -> a.getAuthority().equals("ROLE_SELLER"))
122	                && auth.getAuthorities().stream().noneMatch(a ->
123	                        a.getAuthority().equals("ROLE_WAREHOUSE_STAFF") || a.getAuthority().equals("ROLE_ADMINISTRATOR"));
124	    }
125	
126	    private Long getCurrentUserId() {
127	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
128	        return userRepository.findByUsername(username)
129	                .orElseThrow(() -> new RuntimeException("User not found"))
130	                .getId();
131	    }
132	
133	    private InventoryItemDto toDto(InventoryItem i) {
134	        int available = i.getQuantityOnHand() - i.getQuantityReserved();
135	        int threshold = Math.max(5, i.getLowStockThreshold());
136	        boolean lowStock = available < threshold;
137	        String whName = warehouseRepository.findById(i.getWarehouseId())
138	                .map(w -> w.getName()).orElse(null);
139	        return new InventoryItemDto(i.getId(), i.getProductId(), i.getWarehouseId(), whName,
140	                i.getQuantityOnHand(), i.getQuantityReserved(), i.getQuantityAvailable(),
141	                i.getLowStockThreshold(), lowStock);
142	    }
143	}
