24	@Service
25	@RequiredArgsConstructor
26	public class RiskAnalyticsService {
27	
28	    private static final Logger log = LoggerFactory.getLogger(RiskAnalyticsService.class);
29	
30	    private final RiskEventRepository riskEventRepository;
31	    private final RiskScoreRepository riskScoreRepository;
32	    private final LoginAttemptRepository loginAttemptRepository;
33	    private final IncidentRepository incidentRepository;
34	    private final AppealRepository appealRepository;
35	    private final UserRepository userRepository;
36	    private final ObjectMapper objectMapper;
37	
38	    @Transactional
39	    public RiskEventEntity recordEvent(Long userId, String eventType, String severity, Map<String, Object> details) {
40	        String detailsJson;
41	        try {
42	            detailsJson = details != null ? objectMapper.writeValueAsString(details) : null;
43	        } catch (Exception e) {
44	            detailsJson = null;
45	        }
46	
47	        RiskEventEntity event = RiskEventEntity.builder()
48	                .userId(userId)
49	                .eventType(eventType)
50	                .severity(severity)
51	                .details(detailsJson)
52	                .createdAt(LocalDateTime.now())
53	                .build();
54	
55	        return riskEventRepository.save(event);
56	    }
57	
58	    @Transactional
59	    public RiskScoreEntity computeScore(Long userId) {
60	        LocalDateTime thirtyDaysAgo = LocalDateTime.now().minusDays(30);
61	        List<RiskEventEntity> recentEvents = riskEventRepository.findByUserIdAndCreatedAtAfter(userId, thirtyDaysAgo);
62	
63	        double score = 0.0;
64	        Map<String, Object> factors = new HashMap<>();
65	
66	        // Seller-scoped incident window: complaints filed *against* this user as
67	        // the seller in the last 30 days. This is the signal that matters for
68	        // marketplace risk — a seller getting repeatedly reported by buyers.
69	        // Reporter/assignee linkages (who filed, who triaged) are no longer
70	        // conflated with seller exposure.
71	        List<com.demo.app.persistence.entity.IncidentEntity> sellerRecentIncidents =
72	                incidentRepository.findBySellerIdSince(userId, thirtyDaysAgo);
73	
74	        long sellerEscalatedIncidents = sellerRecentIncidents.stream()
75	                .filter(i -> i.getEscalationLevel() > 0)
76	                .count();
77	        factors.put("seller_escalated_incidents_30d", sellerEscalatedIncidents);
78	        score += sellerEscalatedIncidents * 15.0;
79	
80	        long sellerHighSeverityIncidents = sellerRecentIncidents.stream()
81	                .filter(i -> "HIGH".equals(i.getSeverity()) || "EMERGENCY".equals(i.getSeverity()))
82	                .count();
83	        factors.put("seller_high_severity_incidents_30d", sellerHighSeverityIncidents);
84	        score += sellerHighSeverityIncidents * 12.0;
85	
86	        // Repeat complaint signal: if a seller accumulates >2 incidents in 30d,
87	        // each additional incident stacks.
88	        long sellerIncidentCount = sellerRecentIncidents.size();
89	        long repeatSignal = sellerIncidentCount > 2 ? sellerIncidentCount - 2 : 0;
90	        factors.put("seller_repeat_incident_penalty", repeatSignal);
91	        score += repeatSignal * 8.0;
92	
93	        factors.put("seller_total_incidents_30d", sellerIncidentCount);
94	
95	        // Rejected appeals (staff exceptions denied)
96	        long rejectedAppeals = appealRepository.findByUserId(userId).stream()
97	                .filter(a -> "REJECTED".equals(a.getStatus()))
98	                .filter(a -> a.getResolvedAt() != null && a.getResolvedAt().isAfter(thirtyDaysAgo))
99	                .count();
100	        factors.put("rejected_appeals_30d", rejectedAppeals);
101	        score += rejectedAppeals * 10.0;
102	
103	        // Failed logins (account compromise risk)
104	        UserEntity user = userRepository.findById(userId).orElse(null);
105	        long failedLogins = 0;
106	        if (user != null) {
107	            failedLogins = loginAttemptRepository.countRecentFailed(user.getUsername(), thirtyDaysAgo);
108	        }
109	        factors.put("failed_logins_30d", failedLogins);
110	        score += failedLogins * 3.0;
111	
112	        // High severity risk events
113	        long highSeverityEvents = recentEvents.stream()
114	                .filter(e -> "HIGH".equals(e.getSeverity()) || "CRITICAL".equals(e.getSeverity()))
115	                .count();
116	        factors.put("high_severity_events_30d", highSeverityEvents);
117	        score += highSeverityEvents * 12.0;
118	
119	        // Anomaly categories: specific operational risk signals
120	        long missedPickupCheckins = recentEvents.stream()
121	                .filter(e -> "MISSED_PICKUP_CHECKIN".equals(e.getEventType()))
122	                .count();
123	        factors.put("missed_pickup_checkins_30d", missedPickupCheckins);
124	        score += missedPickupCheckins * 10.0;
125	
126	        long buddyPunchingEvents = recentEvents.stream()
127	                .filter(e -> "BUDDY_PUNCHING".equals(e.getEventType()))
128	                .count();
129	        factors.put("buddy_punching_30d", buddyPunchingEvents);
130	        score += buddyPunchingEvents * 20.0;
131	
132	        long misidentificationEvents = recentEvents.stream()
133	                .filter(e -> "MISIDENTIFICATION".equals(e.getEventType()))
134	                .count();
135	        factors.put("misidentification_30d", misidentificationEvents);
136	        score += misidentificationEvents * 15.0;
137	
138	        score = Math.min(score, 100.0);
139	
140	        String factorsJson;
141	        try {
142	            factorsJson = objectMapper.writeValueAsString(factors);
143	        } catch (Exception e) {
144	            factorsJson = "{}";
145	        }
146	
147	        RiskScoreEntity riskScore = riskScoreRepository.findByUserId(userId)
148	                .orElse(RiskScoreEntity.builder().userId(userId).build());
149	
150	        long openSellerIncidents = sellerRecentIncidents.stream()
151	                .filter(i -> !"RESOLVED".equals(i.getStatus()) && !"CLOSED".equals(i.getStatus()))
152	                .count();
153	
154	        riskScore.setScore(score);
155	        riskScore.setFactors(factorsJson);
156	        riskScore.setComputedAt(LocalDateTime.now());
157	        riskScore.setSellerComplaintCount((int) sellerIncidentCount);
158	        riskScore.setOpenIncidentCount((int) openSellerIncidents);
159	        riskScore.setAppealRejectionCount((int) rejectedAppeals);
160	
161	        return riskScoreRepository.save(riskScore);
162	    }
163	
164	    public RiskScoreEntity getScore(Long userId) {
165	        return riskScoreRepository.findByUserId(userId).orElse(null);
166	    }
167	
168	    public List<RiskScoreEntity> getHighRiskUsers(double threshold) {
169	        return riskScoreRepository.findByScoreGreaterThanOrderByScoreDesc(threshold);
170	    }
171	
172	    public List<RiskEventEntity> getEventsByUser(Long userId) {
173	        return riskEventRepository.findByUserIdOrderByCreatedAtDesc(userId);
174	    }
175	}
