33	    public Appeal create(Long userId, String relatedEntityType, Long relatedEntityId, String reason) {
34	        if (relatedEntityType == null || relatedEntityType.isBlank()) {
35	            throw new IllegalArgumentException("relatedEntityType is required");
36	        }
37	        if (relatedEntityId == null) {
38	            throw new IllegalArgumentException("relatedEntityId is required");
39	        }
40	
41	        // Strict DB-level existence check: the appeal must point at a row that
42	        // actually exists right now. Reject unknown entity types with the same
43	        // error surface so clients cannot probe for valid types via the delta
44	        // between 400s.
45	        String normalizedType = relatedEntityType.trim().toUpperCase(Locale.ROOT);
46	        JpaRepository<?, Long> repository = repositoryFor(normalizedType);
47	        if (repository == null) {
48	            throw new IllegalArgumentException(
49	                    "Unknown relatedEntityType: " + relatedEntityType +
50	                            " (expected one of INCIDENT, PRODUCT, ORDER, LISTING)");
51	        }
52	        if (!repository.existsById(relatedEntityId)) {
53	            throw new ResourceNotFoundException(normalizedType, relatedEntityId);
54	        }
55	
56	        AppealEntity entity = AppealEntity.builder()
57	                .userId(userId)
58	                .relatedEntityType(normalizedType)
59	                .relatedEntityId(relatedEntityId)
60	                .reason(reason)
61	                .status("SUBMITTED")
62	                .createdAt(LocalDateTime.now())
63	                .build();
64	
65	        return appealRepository.save(entity).toModel();
66	    }
67	
68	    private JpaRepository<?, Long> repositoryFor(String type) {
69	        return switch (type) {
70	            case "INCIDENT" -> incidentRepository;
71	            case "PRODUCT" -> productRepository;
72	            case "ORDER" -> orderRepository;
73	            case "LISTING" -> listingRepository;
74	            default -> null;
75	        };
76	    }
77	
78	    public Appeal review(Long appealId, Long reviewerId, String status, String reviewNotes) {
79	        AppealEntity entity = appealRepository.findById(appealId)
80	                .orElseThrow(() -> new ResourceNotFoundException("Appeal", appealId));
81	
82	        StatusTransitions.validate(StatusTransitions.APPEAL, entity.getStatus(), status);
83	
84	        LocalDateTime now = LocalDateTime.now();
85	        entity.setReviewerId(reviewerId);
86	        entity.setReviewNotes(reviewNotes);
87	        entity.setStatus(status);
88	        entity.setReviewedAt(now);
89	
90	        if ("APPROVED".equals(status) || "REJECTED".equals(status)) {
91	            entity.setResolvedAt(now);
92	        }
93	
94	        return appealRepository.save(entity).toModel();
95	    }
