56	        int available = item.getQuantityOnHand() - item.getQuantityReserved();
57	        if (available < quantity) {
58	            throw new InsufficientStockException(available, quantity);
59	        }
60	
61	        item.setQuantityReserved(item.getQuantityReserved() + quantity);
62	        item.setUpdatedAt(LocalDateTime.now());
63	        inventoryItemRepository.save(item);
64	
65	        LocalDateTime now = LocalDateTime.now();
66	        StockReservationEntity reservation = StockReservationEntity.builder()
67	                .inventoryItemId(inventoryItemId)
68	                .userId(userId)
69	                .quantity(quantity)
70	                .status(ReservationStatus.HELD.name())
71	                .idempotencyKey(idempotencyKey)
72	                .expiresAt(now.plusMinutes(holdMinutes))
73	                .createdAt(now)
74	                .build();
75	        stockReservationRepository.save(reservation);
76	
77	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
78	                .inventoryItemId(inventoryItemId)
79	                .warehouseId(item.getWarehouseId())
80	                .movementType(MovementType.RESERVATION_HOLD.name())
81	                .quantity(quantity)
82	                .balanceAfter(item.getQuantityOnHand())
83	                .referenceDocument("reservation:" + reservation.getId())
84	                .operatorId(userId)
85	                .createdAt(now)
86	                .build();
87	        inventoryMovementRepository.save(movement);
88	
89	        return reservation.toModel();
90	    }
91	
92	    public StockReservation confirm(Long reservationId) {
93	        StockReservationEntity reservation = stockReservationRepository.findById(reservationId)
94	                .orElseThrow(() -> new ResourceNotFoundException("Reservation", reservationId));
95	
96	        if (ReservationStatus.CONFIRMED.name().equals(reservation.getStatus())) {
97	            return reservation.toModel();
98	        }
99	
100	        if (!ReservationStatus.HELD.name().equals(reservation.getStatus())) {
101	            throw new IllegalStateException("Reservation cannot be confirmed. Current status: " + reservation.getStatus());
102	        }
103	
104	        LocalDateTime now = LocalDateTime.now();
105	        reservation.setStatus(ReservationStatus.CONFIRMED.name());
106	        reservation.setConfirmedAt(now);
107	        stockReservationRepository.save(reservation);
108	
109	        InventoryItemEntity item = inventoryItemRepository.findById(reservation.getInventoryItemId())
110	                .orElseThrow(() -> new ResourceNotFoundException("Inventory item", reservation.getInventoryItemId()));
111	
112	        item.setQuantityOnHand(item.getQuantityOnHand() - reservation.getQuantity());
113	        item.setQuantityReserved(item.getQuantityReserved() - reservation.getQuantity());
114	        item.setUpdatedAt(now);
115	        inventoryItemRepository.save(item);
116	
117	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
118	                .inventoryItemId(item.getId())
119	                .warehouseId(item.getWarehouseId())
120	                .movementType(MovementType.SHIPMENT.name())
121	                .quantity(-reservation.getQuantity())
122	                .balanceAfter(item.getQuantityOnHand())
123	                .referenceDocument("reservation:" + reservationId)
124	                .operatorId(reservation.getUserId())
125	                .createdAt(now)
126	                .build();
127	        inventoryMovementRepository.save(movement);
128	
129	        return reservation.toModel();
130	    }
131	
132	    public StockReservation cancel(Long reservationId) {
133	        StockReservationEntity reservation = stockReservationRepository.findById(reservationId)
134	                .orElseThrow(() -> new ResourceNotFoundException("Reservation", reservationId));
135	
136	        if (ReservationStatus.CANCELLED.name().equals(reservation.getStatus())
137	                || ReservationStatus.EXPIRED.name().equals(reservation.getStatus())) {
138	            return reservation.toModel();
139	        }
140	
141	        if (!ReservationStatus.HELD.name().equals(reservation.getStatus())) {
142	            throw new IllegalStateException("Reservation cannot be cancelled. Current status: " + reservation.getStatus());
143	        }
144	
145	        LocalDateTime now = LocalDateTime.now();
146	        reservation.setStatus(ReservationStatus.CANCELLED.name());
147	        reservation.setCancelledAt(now);
148	        stockReservationRepository.save(reservation);
149	
150	        InventoryItemEntity item = inventoryItemRepository.findById(reservation.getInventoryItemId())
151	                .orElseThrow(() -> new ResourceNotFoundException("Inventory item", reservation.getInventoryItemId()));
152	
153	        item.setQuantityReserved(item.getQuantityReserved() - reservation.getQuantity());
154	        item.setUpdatedAt(now);
155	        inventoryItemRepository.save(item);
156	
157	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
158	                .inventoryItemId(item.getId())
159	                .warehouseId(item.getWarehouseId())
160	                .movementType(MovementType.RESERVATION_RELEASE.name())
161	                .quantity(reservation.getQuantity())
162	                .balanceAfter(item.getQuantityOnHand())
163	                .referenceDocument("reservation:" + reservationId)
164	                .operatorId(reservation.getUserId())
165	                .createdAt(now)
166	                .build();
167	        inventoryMovementRepository.save(movement);
168	
169	        return reservation.toModel();
170	    }
171	
172	    public void expireOverdueReservations() {
173	        LocalDateTime now = LocalDateTime.now();
174	        List<StockReservationEntity> expired = stockReservationRepository.findExpired(now);
175	
176	        for (StockReservationEntity reservation : expired) {
177	            reservation.setStatus(ReservationStatus.EXPIRED.name());
178	            reservation.setCancelledAt(now);
179	            stockReservationRepository.save(reservation);
180	
181	            InventoryItemEntity item = inventoryItemRepository.findById(reservation.getInventoryItemId())
182	                    .orElse(null);
183	            if (item != null) {
184	                item.setQuantityReserved(item.getQuantityReserved() - reservation.getQuantity());
185	                item.setUpdatedAt(now);
186	                inventoryItemRepository.save(item);
187	
188	                InventoryMovementEntity movement = InventoryMovementEntity.builder()
189	                        .inventoryItemId(item.getId())
190	                        .warehouseId(item.getWarehouseId())
191	                        .movementType(MovementType.RESERVATION_RELEASE.name())
192	                        .quantity(reservation.getQuantity())
193	                        .balanceAfter(item.getQuantityOnHand())
194	                        .referenceDocument("reservation-expired:" + reservation.getId())
195	                        .createdAt(now)
196	                        .build();
197	                inventoryMovementRepository.save(movement);
198	            }
199	        }
200	
201	        if (!expired.isEmpty()) {
202	            log.info("Expired {} overdue reservations", expired.size());
203	        }
204	    }
