206	    public List<StockReservation> getUserHeldReservations(Long userId) {
207	        return stockReservationRepository.findByUserIdAndStatus(userId, ReservationStatus.HELD.name()).stream()
208	                .map(StockReservationEntity::toModel)
209	                .toList();
210	    }
