12	import lombok.RequiredArgsConstructor;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.time.LocalDateTime;
17	import java.util.List;
18	import java.util.Map;
19	import java.util.Optional;
20	import java.util.Set;
21	
22	@Service
23	@RequiredArgsConstructor
24	@Transactional
25	public class FulfillmentService {
26	
27	    private final FulfillmentRepository fulfillmentRepository;
28	    private final FulfillmentStepRepository fulfillmentStepRepository;
29	
30	    private static final Map<FulfillmentStepName, FulfillmentStatus> STEP_TO_STATUS = Map.of(
31	            FulfillmentStepName.PICK, FulfillmentStatus.PICKING,
32	            FulfillmentStepName.PACK, FulfillmentStatus.PACKING,
33	            FulfillmentStepName.SHIP, FulfillmentStatus.SHIPPED,
34	            FulfillmentStepName.DELIVER, FulfillmentStatus.DELIVERED
35	    );
36	
37	    private static final Map<FulfillmentStepName, Set<FulfillmentStatus>> ALLOWED_TRANSITIONS = Map.of(
38	            FulfillmentStepName.PICK, Set.of(FulfillmentStatus.PENDING),
39	            FulfillmentStepName.PACK, Set.of(FulfillmentStatus.PICKING),
40	            FulfillmentStepName.SHIP, Set.of(FulfillmentStatus.PACKING),
41	            FulfillmentStepName.DELIVER, Set.of(FulfillmentStatus.SHIPPED)
42	    );
43	
44	    public Fulfillment create(Long orderId, Long warehouseId, String idempotencyKey) {
45	        Optional<FulfillmentEntity> existing = fulfillmentRepository.findByIdempotencyKey(idempotencyKey);
46	        if (existing.isPresent()) {
47	            return existing.get().toModel();
48	        }
49	
50	        LocalDateTime now = LocalDateTime.now();
51	        FulfillmentEntity entity = FulfillmentEntity.builder()
52	                .orderId(orderId)
53	                .warehouseId(warehouseId)
54	                .status(FulfillmentStatus.PENDING.name())
55	                .idempotencyKey(idempotencyKey)
56	                .createdAt(now)
57	                .updatedAt(now)
58	                .build();
59	        return fulfillmentRepository.save(entity).toModel();
60	    }
61	
62	    public Fulfillment advanceStep(Long fulfillmentId, String stepName, Long operatorId, String notes) {
63	        FulfillmentEntity fulfillment = fulfillmentRepository.findById(fulfillmentId)
64	                .orElseThrow(() -> new ResourceNotFoundException("Fulfillment", fulfillmentId));
65	
66	        FulfillmentStepName step = FulfillmentStepName.valueOf(stepName);
67	        FulfillmentStatus currentStatus = FulfillmentStatus.valueOf(fulfillment.getStatus());
68	
69	        Set<FulfillmentStatus> allowed = ALLOWED_TRANSITIONS.get(step);
70	        if (allowed == null || !allowed.contains(currentStatus)) {
71	            throw new IllegalStateException("Cannot perform step " + stepName + " when fulfillment status is " + currentStatus);
72	        }
73	
74	        LocalDateTime now = LocalDateTime.now();
75	        FulfillmentStepEntity stepEntity = FulfillmentStepEntity.builder()
76	                .fulfillmentId(fulfillmentId)
77	                .stepName(step.name())
78	                .status("COMPLETED")
79	                .operatorId(operatorId)
80	                .notes(notes)
81	                .createdAt(now)
82	                .completedAt(now)
83	                .build();
84	        fulfillmentStepRepository.save(stepEntity);
85	
86	        FulfillmentStatus newStatus = STEP_TO_STATUS.get(step);
87	        fulfillment.setStatus(newStatus.name());
88	        fulfillment.setUpdatedAt(now);
89	        fulfillmentRepository.save(fulfillment);
90	
91	        return fulfillment.toModel();
92	    }
93	
94	    public Fulfillment cancelFulfillment(Long fulfillmentId) {
95	        FulfillmentEntity fulfillment = fulfillmentRepository.findById(fulfillmentId)
96	                .orElseThrow(() -> new ResourceNotFoundException("Fulfillment", fulfillmentId));
97	
98	        FulfillmentStatus currentStatus = FulfillmentStatus.valueOf(fulfillment.getStatus());
99	        if (currentStatus != FulfillmentStatus.PENDING && currentStatus != FulfillmentStatus.PICKING) {
100	            throw new IllegalStateException("Fulfillment can only be cancelled when PENDING or PICKING. Current: " + currentStatus);
101	        }
102	
103	        fulfillment.setStatus(FulfillmentStatus.CANCELLED.name());
104	        fulfillment.setUpdatedAt(LocalDateTime.now());
105	        return fulfillmentRepository.save(fulfillment).toModel();
106	    }
107	
108	    public Fulfillment getById(Long id) {
109	        return fulfillmentRepository.findById(id)
110	                .orElseThrow(() -> new ResourceNotFoundException("Fulfillment", id))
111	                .toModel();
112	    }
113	
114	    public Fulfillment getByOrder(Long orderId) {
115	        return fulfillmentRepository.findByOrderId(orderId)
116	                .orElseThrow(() -> new ResourceNotFoundException("Fulfillment for order", orderId))
117	                .toModel();
118	    }
119	
120	    public List<FulfillmentStep> getSteps(Long fulfillmentId) {
121	        return fulfillmentStepRepository.findByFulfillmentIdOrderByCreatedAtAsc(fulfillmentId).stream()
122	                .map(FulfillmentStepEntity::toModel)
123	                .toList();
124	    }
125	}
