44	    public BenefitIssuanceLedgerEntity issueBenefit(Long memberId, Long benefitItemId, Long issuedByUserId, String reference, String referenceType, Long referenceId) {
45	        if (referenceType == null || referenceType.isBlank()) {
46	            throw new IllegalArgumentException("referenceType is required. Must be ORDER or INCIDENT.");
47	        }
48	
49	        Long orderId = null;
50	        Long incidentId = null;
51	
52	        if ("ORDER".equals(referenceType)) {
53	                if (referenceId == null || !orderRepository.existsById(referenceId)) {
54	                    throw new ResourceNotFoundException("Order", referenceId);
55	                }
56	                orderId = referenceId;
57	            } else if ("INCIDENT".equals(referenceType)) {
58	                if (referenceId == null || !incidentRepository.existsById(referenceId)) {
59	                    throw new ResourceNotFoundException("Incident", referenceId);
60	                }
61	                incidentId = referenceId;
62	            } else {
63	            throw new IllegalArgumentException("Invalid referenceType: " + referenceType + ". Must be ORDER or INCIDENT.");
64	        }
65	
66	        BenefitIssuanceLedgerEntity entity = BenefitIssuanceLedgerEntity.builder()
67	                .memberId(memberId)
68	                .benefitItemId(benefitItemId)
69	                .issuedBy(issuedByUserId)
70	                .reference(reference)
71	                .referenceType(referenceType)
72	                .referenceId(referenceId)
73	                .orderId(orderId)
74	                .incidentId(incidentId)
75	                .issuedAt(LocalDateTime.now())
76	                .build();
77	        return benefitIssuanceLedgerRepository.save(entity);
78	    }
79	
80	    public BenefitRedemptionLedgerEntity redeemBenefit(Long memberId, Long benefitItemId, String reference, Long orderCategoryId, Long orderSellerId, String referenceType, Long referenceId) {
81	        BenefitItemEntity item = benefitItemRepository.findById(benefitItemId)
82	                .orElseThrow(() -> new com.demo.app.domain.exception.ResourceNotFoundException("Benefit item", benefitItemId));
83	
84	        // Check mutual exclusion: if this item has an exclusion group, verify no other
85	        // item from the same group has been redeemed with the same reference (transaction)
86	        if (item.getExclusionGroup() != null && reference != null) {
87	            List<BenefitRedemptionLedgerEntity> existing = benefitRedemptionLedgerRepository.findByMemberId(memberId);
88	            boolean conflict = existing.stream().anyMatch(r ->
89	                    reference.equals(r.getReference()) && benefitItemRepository.findById(r.getBenefitItemId())
90	                            .map(bi -> item.getExclusionGroup().equals(bi.getExclusionGroup()) && !bi.getId().equals(item.getId()))
91	                            .orElse(false));
92	            if (conflict) {
93	                throw new com.demo.app.domain.exception.ConflictException(
94	                        "Cannot redeem: another benefit in exclusion group '" + item.getExclusionGroup() + "' is already applied to this transaction");
95	            }
96	        }
97	
98	        // Enforce date window
99	        LocalDateTime now = LocalDateTime.now();
100	        if (item.getValidFrom() != null && now.isBefore(item.getValidFrom())) {
101	            throw new com.demo.app.domain.exception.ConflictException("Benefit not yet active. Valid from: " + item.getValidFrom());
102	        }
103	        if (item.getValidTo() != null && now.isAfter(item.getValidTo())) {
104	            throw new com.demo.app.domain.exception.ConflictException("Benefit has expired. Valid until: " + item.getValidTo());
105	        }
106	
107	        // Enforce category scope
108	        if (item.getCategoryId() != null && orderCategoryId != null
109	                && !item.getCategoryId().equals(orderCategoryId)) {
110	            throw new com.demo.app.domain.exception.ConflictException(
111	                    "Benefit is restricted to category " + item.getCategoryId() + " but order is category " + orderCategoryId);
112	        }
113	
114	        // Enforce seller scope
115	        if (item.getSellerId() != null && orderSellerId != null
116	                && !item.getSellerId().equals(orderSellerId)) {
117	            throw new com.demo.app.domain.exception.ConflictException(
118	                    "Benefit is restricted to seller " + item.getSellerId() + " but order is from seller " + orderSellerId);
119	        }
120	
121	        if (referenceType == null || referenceType.isBlank()) {
122	            throw new IllegalArgumentException("referenceType is required. Must be ORDER or INCIDENT.");
123	        }
124	
125	        Long orderId = null;
126	        Long incidentId = null;
127	
128	        if ("ORDER".equals(referenceType)) {
129	            if (referenceId == null || !orderRepository.existsById(referenceId)) {
130	                throw new ResourceNotFoundException("Order", referenceId);
131	            }
132	            orderId = referenceId;
133	        } else if ("INCIDENT".equals(referenceType)) {
134	            if (referenceId == null || !incidentRepository.existsById(referenceId)) {
135	                throw new ResourceNotFoundException("Incident", referenceId);
136	            }
137	            incidentId = referenceId;
138	        } else {
139	            throw new IllegalArgumentException("Invalid referenceType: " + referenceType + ". Must be ORDER or INCIDENT.");
140	        }
141	
142	        BenefitRedemptionLedgerEntity entity = BenefitRedemptionLedgerEntity.builder()
143	                .memberId(memberId)
144	                .benefitItemId(benefitItemId)
145	                .reference(reference)
146	                .referenceType(referenceType)
147	                .referenceId(referenceId)
148	                .orderId(orderId)
149	                .incidentId(incidentId)
150	                .redeemedAt(LocalDateTime.now())
151	                .build();
152	        return benefitRedemptionLedgerRepository.save(entity);
153	    }
154	}
