13	import com.demo.app.persistence.entity.BenefitRedemptionLedgerEntity;
14	import com.demo.app.persistence.repository.UserRepository;
15	import lombok.RequiredArgsConstructor;
16	import org.springframework.http.ResponseEntity;
17	import org.springframework.security.access.prepost.PreAuthorize;
18	import org.springframework.security.core.context.SecurityContextHolder;
19	import org.springframework.web.bind.annotation.*;
20	
21	import java.util.List;
22	
23	@RestController
24	@RequestMapping("/api/benefits")
25	@RequiredArgsConstructor
26	public class BenefitController {
27	
28	    private final BenefitService benefitService;
29	    private final MemberProfileService memberProfileService;
30	    private final UserRepository userRepository;
31	
32	    @GetMapping("/packages/tier/{tierId}")
33	    public ResponseEntity<List<BenefitPackageDto>> getPackagesByTier(@PathVariable Long tierId) {
34	        List<BenefitPackageDto> packages = benefitService.getPackagesByTier(tierId).stream()
35	                .map(this::toPackageDto)
36	                .toList();
37	        return ResponseEntity.ok(packages);
38	    }
39	
40	    @GetMapping("/items/package/{packageId}")
41	    public ResponseEntity<List<BenefitItemDto>> getItemsByPackage(@PathVariable Long packageId) {
42	        List<BenefitItemDto> items = benefitService.getItemsByPackage(packageId).stream()
43	                .map(this::toItemDto)
44	                .toList();
45	        return ResponseEntity.ok(items);
46	    }
47	
48	    @PostMapping("/issue")
49	    @PreAuthorize("hasAnyRole('MODERATOR', 'ADMINISTRATOR')")
50	    public ResponseEntity<Void> issueBenefit(@RequestBody IssueBenefitRequest request) {
51	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
52	        Long issuedByUserId = userRepository.findByUsername(username)
53	                .orElseThrow(() -> new RuntimeException("User not found: " + username))
54	                .getId();
55	
56	        benefitService.issueBenefit(request.memberId(), request.benefitItemId(), issuedByUserId, request.reference(), request.referenceType(), request.referenceId());
57	        return ResponseEntity.ok().build();
58	    }
59	
60	    @PostMapping("/redeem")
61	    @PreAuthorize("hasAnyRole('MEMBER', 'SELLER', 'MODERATOR', 'ADMINISTRATOR')")
62	    public ResponseEntity<Void> redeemBenefit(@RequestBody RedeemBenefitRequest request) {
63	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
64	        Long userId = userRepository.findByUsername(username)
65	                .orElseThrow(() -> new RuntimeException("User not found: " + username))
66	                .getId();
67	
68	        MemberProfile profile = memberProfileService.getByUserId(userId);
69	        benefitService.redeemBenefit(profile.getId(), request.benefitItemId(), request.reference(), request.categoryId(), request.sellerId(), request.referenceType(), request.referenceId());
70	        return ResponseEntity.ok().build();
71	    }
72	
73	    private BenefitPackageDto toPackageDto(BenefitPackage pkg) {
74	        return new BenefitPackageDto(
75	                pkg.getId(),
76	                pkg.getTierId(),
77	                pkg.getName(),
78	                pkg.getDescription(),
79	                pkg.isActive()
80	        );
81	    }
82	
83	    private BenefitItemDto toItemDto(BenefitItem item) {
84	        return new BenefitItemDto(
85	                item.getId(),
86	                item.getPackageId(),
87	                item.getBenefitType(),
88	                item.getBenefitValue(),
89	                item.getScope(),
90	                item.getExclusionGroup(),
91	                item.getCategoryId(),
92	                item.getSellerId(),
93	                item.getValidFrom(),
94	                item.getValidTo()
95	        );
96	    }
97	}
