5	import { useAuthStore } from '@/state/authStore';
6	
7	const slugify = (text: string): string =>
8	  text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
9	
10	const statusBadge = (status: string) => {
11	  switch (status) {
12	    case 'PUBLISHED': return 'badge-success';
13	    case 'DRAFT': return 'badge-warning';
14	    case 'ARCHIVED': return 'badge-neutral';
15	    default: return 'badge-info';
16	  }
17	};
18	
19	const SellerListingsPage: React.FC = () => {
20	  const { user } = useAuthStore();
21	  const [listings, setListings] = useState<Listing[]>([]);
22	  const [products, setProducts] = useState<Product[]>([]);
23	  const [loading, setLoading] = useState(true);
24	  const [error, setError] = useState('');
25	  const [showForm, setShowForm] = useState(false);
26	  const [formLoading, setFormLoading] = useState(false);
27	  const [form, setForm] = useState({
28	    productId: '',
29	    title: '',
30	    slug: '',
31	    summary: '',
32	    tags: '',
33	  });
34	
35	  useEffect(() => {
36	    loadData();
37	  }, []);
38	
39	  const loadData = async () => {
40	    try {
41	      const [listingsData, productsData] = await Promise.all([
42	        getListings(),
43	        getProducts(),
44	      ]);
45	      setListings(listingsData);
46	      // Filter products to the seller's own if SELLER role
47	      const filtered = user?.role === 'SELLER'
48	        ? productsData.filter((p) => p.sellerId === user.id)
49	        : productsData;
50	      setProducts(filtered);
51	    } catch {
52	      setError('Failed to load data');
53	    } finally {
54	      setLoading(false);
55	    }
56	  };
57	
58	  const handleTitleChange = (title: string) => {
59	    setForm({ ...form, title, slug: slugify(title) });
60	  };
61	
62	  const handleSubmit = async (e: React.FormEvent) => {
63	    e.preventDefault();
64	    if (!form.productId || !form.title) {
65	      setError('Product and title are required');
66	      return;
67	    }
68	    setFormLoading(true);
69	    setError('');
70	    try {
71	      const tags = form.tags
72	        .split(',')
73	        .map((t) => t.trim())
74	        .filter(Boolean);
