39	  status: string,
40	  closureCode?: string,
41	): Promise<Incident> {
42	  const payload: { status: string; closureCode?: string } = { status };
43	  // Backend rejects RESOLVED without a closureCode; forward whatever the
44	  // caller supplied so the contract isn't implicitly lossy.
45	  if (closureCode !== undefined && closureCode !== null && closureCode !== '') {
46	    payload.closureCode = closureCode;
