31	                    .actorId(actorId)
32	                    .oldValue(oldValueJson)
33	                    .newValue(newValueJson)
34	                    .ipAddress(ipAddress)
35	                    .createdAt(LocalDateTime.now())
36	                    .retentionExpiresAt(LocalDateTime.now().plusYears(2))
37	                    .build();
38	
39	            auditLogRepository.save(entity);
40	        } catch (Exception e) {
41	            throw new RuntimeException("Failed to create audit log", e);
42	        }
43	    }
