104	    @PreAuthorize("hasAnyRole('MODERATOR', 'ADMINISTRATOR')")
105	    public ResponseEntity<ListingDto> publish(@PathVariable Long id) {
106	        enforceListingOwnership(id);
107	        return ResponseEntity.ok(toDto(listingService.publish(id)));
108	    }
109	
110	    @PostMapping("/{id}/archive")
111	    @PreAuthorize("hasAnyRole('MODERATOR', 'ADMINISTRATOR')")
112	    public ResponseEntity<ListingDto> archive(@PathVariable Long id) {
113	        enforceListingOwnership(id);
114	        return ResponseEntity.ok(toDto(listingService.archive(id)));
115	    }
116	
117	    private void enforceListingOwnership(Long listingId) {
118	        if (isPrivileged()) return;
119	        Listing listing = listingService.getById(listingId);
120	        Product product = productService.getById(listing.getProductId());
121	        if (!product.getSellerId().equals(getCurrentUserId())) {
122	            throw new OwnershipViolationException("You can only modify your own listings");
123	        }
124	    }
125	
126	    private boolean isPrivileged() {
127	        var auth = SecurityContextHolder.getContext().getAuthentication();
128	        return auth.getAuthorities().stream().anyMatch(a ->
129	                a.getAuthority().equals("ROLE_ADMINISTRATOR") ||
130	                a.getAuthority().equals("ROLE_MODERATOR"));
131	    }
132	
133	    private Long getCurrentUserId() {
134	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
135	        return userRepository.findByUsername(username)
136	                .orElseThrow(() -> new RuntimeException("User not found"))
137	                .getId();
138	    }
139	
140	    private ListingDto toDto(Listing l) {
141	        return new ListingDto(l.getId(), l.getProductId(), l.getTitle(), l.getSlug(), l.getSummary(),
142	                l.getTags() != null ? l.getTags().toArray(new String[0]) : null,
143	                l.isFeatured(), l.getViewCount(), l.getWeeklyViews(), l.getSearchRank(),
144	                l.getStatus() != null ? l.getStatus().name() : null, l.getPublishedAt(),
145	                l.getNeighborhood(), l.getLatitude(), l.getLongitude(),
146	                l.getPrice(), l.getSqft(), l.getLayout(),
147	                l.getAvailableFrom() != null ? l.getAvailableFrom().toString() : null,
148	                l.getAvailableTo() != null ? l.getAvailableTo().toString() : null);
149	    }
