34	    public MemberProfile createProfile(Long userId, String phone) {
35	        MemberTier bronzeTier = memberTierService.getAll().stream()
36	                .filter(t -> t.getRank() == 1)
37	                .findFirst()
38	                .orElseThrow(() -> new RuntimeException("Bronze tier (rank 1) not found"));
