43	                .totalSpend(0)
44	                .joinedAt(LocalDateTime.now())
45	                .updatedAt(LocalDateTime.now())
46	                .build();
47	
48	        if (phone != null && !phone.isBlank()) {
49	            entity.setPhoneEncrypted(fieldEncryptor.encrypt(phone));
50	            entity.setPhoneMasked(PhoneMaskUtil.mask(phone));
51	        }
52	
53	        return memberProfileRepository.save(entity).toModel();
54	    }
55	
56	    public MemberProfile updatePhone(Long userId, String phone) {
57	        MemberProfileEntity entity = memberProfileRepository.findByUserId(userId)
58	                .orElseThrow(() -> new RuntimeException("Member profile not found for user: " + userId));
59	
60	        entity.setPhoneEncrypted(fieldEncryptor.encrypt(phone));
