62	        entity.setUpdatedAt(LocalDateTime.now());
63	
64	        return memberProfileRepository.save(entity).toModel();
65	    }
66	
67	    public MemberProfile addSpend(Long userId, int amount, String reference) {
68	        MemberProfileEntity entity = memberProfileRepository.findByUserId(userId)
69	                .orElseThrow(() -> new RuntimeException("Member profile not found for user: " + userId));
70	
71	        int newBalance = entity.getTotalSpend() + amount;
72	        entity.setTotalSpend(newBalance);
73	        entity.setUpdatedAt(LocalDateTime.now());
74	
75	        PointsLedgerEntity ledgerEntry = PointsLedgerEntity.builder()
76	                .memberId(entity.getId())
77	                .amount(amount)
78	                .spendAfter(newBalance)
79	                .entryType("EARNED")
80	                .reference(reference)
81	                .createdAt(LocalDateTime.now())
82	                .build();
83	        pointsLedgerRepository.save(ledgerEntry);
84	
85	        MemberTier newTier = memberTierService.getTierForSpend(newBalance);
