115	        MemberTier newTier = memberTierService.getTierForSpend(newBalance);
116	        if (!newTier.getId().equals(entity.getTierId())) {
117	            entity.setTierId(newTier.getId());
118	        }
119	
120	        return memberProfileRepository.save(entity).toModel();
121	    }
