80	    public BenefitRedemptionLedgerEntity redeemBenefit(Long memberId, Long benefitItemId, String reference, Long orderCategoryId, Long orderSellerId, String referenceType, Long referenceId) {
81	        BenefitItemEntity item = benefitItemRepository.findById(benefitItemId)
82	                .orElseThrow(() -> new com.demo.app.domain.exception.ResourceNotFoundException("Benefit item", benefitItemId));
83	
84	        // Check mutual exclusion: if this item has an exclusion group, verify no other
85	        // item from the same group has been redeemed with the same reference (transaction)
86	        if (item.getExclusionGroup() != null && reference != null) {
87	            List<BenefitRedemptionLedgerEntity> existing = benefitRedemptionLedgerRepository.findByMemberId(memberId);
88	            boolean conflict = existing.stream().anyMatch(r ->
89	                    reference.equals(r.getReference()) && benefitItemRepository.findById(r.getBenefitItemId())
90	                            .map(bi -> item.getExclusionGroup().equals(bi.getExclusionGroup()) && !bi.getId().equals(item.getId()))
91	                            .orElse(false));
92	            if (conflict) {
93	                throw new com.demo.app.domain.exception.ConflictException(
94	                        "Cannot redeem: another benefit in exclusion group '" + item.getExclusionGroup() + "' is already applied to this transaction");
95	            }
96	        }
97	
98	        // Enforce date window
99	        LocalDateTime now = LocalDateTime.now();
100	        if (item.getValidFrom() != null && now.isBefore(item.getValidFrom())) {
101	            throw new com.demo.app.domain.exception.ConflictException("Benefit not yet active. Valid from: " + item.getValidFrom());
