104	            throw new com.demo.app.domain.exception.ConflictException("Benefit has expired. Valid until: " + item.getValidTo());
105	        }
106	
107	        // Enforce category scope
108	        if (item.getCategoryId() != null && orderCategoryId != null
109	                && !item.getCategoryId().equals(orderCategoryId)) {
110	            throw new com.demo.app.domain.exception.ConflictException(
111	                    "Benefit is restricted to category " + item.getCategoryId() + " but order is category " + orderCategoryId);
112	        }
113	
114	        // Enforce seller scope
115	        if (item.getSellerId() != null && orderSellerId != null
116	                && !item.getSellerId().equals(orderSellerId)) {
117	            throw new com.demo.app.domain.exception.ConflictException(
118	                    "Benefit is restricted to seller " + item.getSellerId() + " but order is from seller " + orderSellerId);
119	        }
120	
121	        if (referenceType == null || referenceType.isBlank()) {
122	            throw new IllegalArgumentException("referenceType is required. Must be ORDER or INCIDENT.");
123	        }
124	
125	        Long orderId = null;
126	        Long incidentId = null;
