1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.enums.ListingStatus;
4	import com.demo.app.domain.model.Listing;
5	import com.demo.app.persistence.entity.ListingEntity;
6	import com.demo.app.persistence.repository.ListingRepository;
7	import lombok.RequiredArgsConstructor;
8	import org.springframework.stereotype.Service;
9	import org.springframework.transaction.annotation.Transactional;
10	
11	import java.time.LocalDateTime;
12	import java.util.List;
13	
14	@Service
15	@RequiredArgsConstructor
16	@Transactional
17	public class ListingService {
18	
19	    private final ListingRepository listingRepository;
20	
21	    public List<Listing> getPublished() {
22	        return listingRepository.findPublishedByRank().stream()
23	                .map(ListingEntity::toModel)
24	                .toList();
25	    }
26	
27	    public Listing getBySlug(String slug) {
28	        return listingRepository.findBySlug(slug)
29	                .orElseThrow(() -> new RuntimeException("Listing not found with slug: " + slug))
30	                .toModel();
31	    }
32	
33	    public Listing getById(Long id) {
34	        return listingRepository.findById(id)
35	                .orElseThrow(() -> new RuntimeException("Listing not found: " + id))
36	                .toModel();
37	    }
38	
39	    public Listing getByProduct(Long productId) {
40	        return listingRepository.findByProductId(productId)
41	                .orElseThrow(() -> new RuntimeException("Listing not found for product: " + productId))
42	                .toModel();
43	    }
44	
45	    public Listing create(Listing listing) {
46	        if (listingRepository.findBySlug(listing.getSlug()).isPresent()) {
47	            throw new RuntimeException("Listing with slug '" + listing.getSlug() + "' already exists");
48	        }
49	
50	        LocalDateTime now = LocalDateTime.now();
51	        ListingEntity entity = ListingEntity.builder()
52	                .productId(listing.getProductId())
53	                .title(listing.getTitle())
54	                .slug(listing.getSlug())
55	                .summary(listing.getSummary())
56	                .tags(listing.getTags() != null ? listing.getTags().toArray(new String[0]) : null)
57	                .featured(listing.isFeatured())
58	                .viewCount(0)
59	                .searchRank(0.0)
60	                .metadata(listing.getMetadata())
61	                .status(ListingStatus.DRAFT.name())
62	                .createdAt(now)
63	                .updatedAt(now)
64	                .build();
65	        return listingRepository.save(entity).toModel();
66	    }
67	
68	    public Listing update(Long id, Listing listing) {
69	        ListingEntity entity = listingRepository.findById(id)
70	                .orElseThrow(() -> new RuntimeException("Listing not found: " + id));
71	
72	        entity.setTitle(listing.getTitle());
73	        entity.setSlug(listing.getSlug());
74	        entity.setSummary(listing.getSummary());
75	        entity.setTags(listing.getTags() != null ? listing.getTags().toArray(new String[0]) : null);
76	        entity.setFeatured(listing.isFeatured());
77	        entity.setMetadata(listing.getMetadata());
78	        entity.setUpdatedAt(LocalDateTime.now());
79	        return listingRepository.save(entity).toModel();
80	    }
81	
82	    public Listing publish(Long id) {
83	        ListingEntity entity = listingRepository.findById(id)
84	                .orElseThrow(() -> new RuntimeException("Listing not found: " + id));
85	
86	        entity.setStatus(ListingStatus.PUBLISHED.name());
87	        entity.setPublishedAt(LocalDateTime.now());
88	        entity.setUpdatedAt(LocalDateTime.now());
89	        return listingRepository.save(entity).toModel();
90	    }
91	
92	    public Listing archive(Long id) {
93	        ListingEntity entity = listingRepository.findById(id)
94	                .orElseThrow(() -> new RuntimeException("Listing not found: " + id));
95	
96	        entity.setStatus(ListingStatus.ARCHIVED.name());
97	        entity.setUpdatedAt(LocalDateTime.now());
98	        return listingRepository.save(entity).toModel();
99	    }
100	
101	    public void incrementViewCount(Long id) {
102	        ListingEntity entity = listingRepository.findById(id)
103	                .orElseThrow(() -> new RuntimeException("Listing not found: " + id));
104	
105	        entity.setViewCount(entity.getViewCount() + 1);
106	        entity.setWeeklyViews(entity.getWeeklyViews() + 1);
107	        entity.setUpdatedAt(LocalDateTime.now());
108	        listingRepository.save(entity);
109	    }
110	
111	    public List<Listing> searchBasic(String query) {
112	        String pattern = "%" + query + "%";
113	        return listingRepository.findByStatus(ListingStatus.PUBLISHED.name()).stream()
114	                .filter(e -> (e.getTitle() != null && e.getTitle().toLowerCase().contains(query.toLowerCase()))
115	                        || (e.getSummary() != null && e.getSummary().toLowerCase().contains(query.toLowerCase())))
116	                .map(ListingEntity::toModel)
117	                .toList();
118	    }
119	
120	    @Transactional(readOnly = true)
121	    public List<Listing> searchAdvanced(String query, String neighborhood,
122	                                         Double userLat, Double userLng, Double radiusMiles,
123	                                         java.time.LocalDate availableAfter,
124	                                         java.time.LocalDate availableBefore,
125	                                         java.math.BigDecimal minPrice, java.math.BigDecimal maxPrice,
126	                                         Integer minSqft, Integer maxSqft,
127	                                         String layout) {
128	        List<ListingEntity> all = listingRepository.findByStatus("PUBLISHED");
129	
130	        return all.stream()
131	                .filter(l -> query == null || query.isBlank()
132	                        || l.getTitle().toLowerCase().contains(query.toLowerCase())
133	                        || (l.getSummary() != null && l.getSummary().toLowerCase().contains(query.toLowerCase())))
134	                .filter(l -> neighborhood == null || neighborhood.isBlank()
135	                        || (l.getNeighborhood() != null && l.getNeighborhood().equalsIgnoreCase(neighborhood)))
136	                .filter(l -> availableAfter == null
137	                        || (l.getAvailableFrom() != null && !l.getAvailableFrom().isAfter(availableAfter)))
138	                .filter(l -> availableBefore == null
139	                        || (l.getAvailableTo() != null && !l.getAvailableTo().isBefore(availableBefore)))
140	                .filter(l -> minPrice == null
141	                        || (l.getPrice() != null && l.getPrice().compareTo(minPrice) >= 0))
142	                .filter(l -> maxPrice == null
143	                        || (l.getPrice() != null && l.getPrice().compareTo(maxPrice) <= 0))
144	                .filter(l -> minSqft == null
145	                        || (l.getSqft() != null && l.getSqft() >= minSqft))
146	                .filter(l -> maxSqft == null
147	                        || (l.getSqft() != null && l.getSqft() <= maxSqft))
148	                .filter(l -> layout == null || layout.isBlank()
149	                        || (l.getLayout() != null && l.getLayout().equalsIgnoreCase(layout)))
150	                .filter(l -> {
151	                    if (radiusMiles == null || userLat == null || userLng == null) return true;
152	                    if (l.getLatitude() == null || l.getLongitude() == null) return false;
153	                    double distKm = haversine(userLat, userLng, l.getLatitude(), l.getLongitude());
154	                    double distMiles = distKm / 1.609344;
155	                    return distMiles <= radiusMiles;
156	                })
157	                .sorted((a, b) -> {
158	                    if (userLat != null && userLng != null
159	                            && a.getLatitude() != null && a.getLongitude() != null
160	                            && b.getLatitude() != null && b.getLongitude() != null) {
161	                        double distA = haversine(userLat, userLng, a.getLatitude(), a.getLongitude());
162	                        double distB = haversine(userLat, userLng, b.getLatitude(), b.getLongitude());
163	                        return Double.compare(distA, distB);
164	                    }
165	                    return Double.compare(b.getSearchRank(), a.getSearchRank());
166	                })
167	                .map(ListingEntity::toModel)
168	                .toList();
169	    }
170	
171	    @Transactional
172	    public void refreshWeeklyViews() {
173	        // Decay weekly views by 15% daily to approximate a rolling 7-day window
174	        listingRepository.findAll().forEach(listing -> {
175	            long decayed = (long) (listing.getWeeklyViews() * 0.85);
176	            listing.setWeeklyViews(decayed);
177	            listing.setUpdatedAt(java.time.LocalDateTime.now());
178	            listingRepository.save(listing);
179	        });
180	    }
181	
182	    private double haversine(double lat1, double lon1, double lat2, double lon2) {
183	        double R = 6371.0; // km
184	        double dLat = Math.toRadians(lat2 - lat1);
185	        double dLon = Math.toRadians(lon2 - lon1);
186	        double a = Math.sin(dLat / 2) * Math.sin(dLat / 2)
187	                + Math.cos(Math.toRadians(lat1)) * Math.cos(Math.toRadians(lat2))
188	                * Math.sin(dLon / 2) * Math.sin(dLon / 2);
189	        return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
190	    }
191	}
