1	import React, { useState, useEffect } from 'react';
2	import { getListings, createListing } from '@/api/listings';
3	import { getProducts } from '@/api/products';
4	import { Listing, Product } from '@/api/types';
5	import { useAuthStore } from '@/state/authStore';
6	
7	const slugify = (text: string): string =>
8	  text.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
9	
10	const statusBadge = (status: string) => {
11	  switch (status) {
12	    case 'PUBLISHED': return 'badge-success';
13	    case 'DRAFT': return 'badge-warning';
14	    case 'ARCHIVED': return 'badge-neutral';
15	    default: return 'badge-info';
16	  }
17	};
18	
19	const SellerListingsPage: React.FC = () => {
20	  const { user } = useAuthStore();
21	  const [listings, setListings] = useState<Listing[]>([]);
22	  const [products, setProducts] = useState<Product[]>([]);
23	  const [loading, setLoading] = useState(true);
24	  const [error, setError] = useState('');
25	  const [showForm, setShowForm] = useState(false);
26	  const [formLoading, setFormLoading] = useState(false);
27	  const [form, setForm] = useState({
28	    productId: '',
29	    title: '',
30	    slug: '',
31	    summary: '',
32	    tags: '',
33	  });
34	
35	  useEffect(() => {
36	    loadData();
37	  }, []);
38	
39	  const loadData = async () => {
40	    try {
41	      const [listingsData, productsData] = await Promise.all([
42	        getListings(),
43	        getProducts(),
44	      ]);
45	      setListings(listingsData);
46	      // Filter products to the seller's own if SELLER role
47	      const filtered = user?.role === 'SELLER'
48	        ? productsData.filter((p) => p.sellerId === user.id)
49	        : productsData;
50	      setProducts(filtered);
51	    } catch {
52	      setError('Failed to load data');
53	    } finally {
54	      setLoading(false);
55	    }
56	  };
57	
58	  const handleTitleChange = (title: string) => {
59	    setForm({ ...form, title, slug: slugify(title) });
60	  };
61	
62	  const handleSubmit = async (e: React.FormEvent) => {
63	    e.preventDefault();
64	    if (!form.productId || !form.title) {
65	      setError('Product and title are required');
66	      return;
67	    }
68	    setFormLoading(true);
69	    setError('');
70	    try {
71	      const tags = form.tags
72	        .split(',')
73	        .map((t) => t.trim())
74	        .filter(Boolean);
75	      await createListing({
76	        productId: parseInt(form.productId),
77	        title: form.title,
78	        slug: form.slug || slugify(form.title),
79	        summary: form.summary,
80	        tags,
81	      });
82	      setForm({ productId: '', title: '', slug: '', summary: '', tags: '' });
83	      setShowForm(false);
84	      await loadData();
85	    } catch {
86	      setError('Failed to create listing');
87	    } finally {
88	      setFormLoading(false);
89	    }
90	  };
91	
92	  if (loading) return <div className="page-loading">Loading...</div>;
93	
94	  return (
95	    <div className="page">
96	      <div className="page-header">
97	        <h1>My Listings</h1>
98	        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
99	          {showForm ? 'Cancel' : 'Create Listing'}
100	        </button>
101	      </div>
102	
103	      {error && <div className="alert alert-danger">{error}</div>}
104	
105	      {showForm && (
106	        <div className="card" style={{ marginBottom: '1.5rem' }}>
107	          <div className="card-header">New Listing</div>
108	          <div className="card-body">
109	            <form onSubmit={handleSubmit}>
110	              <div className="form-group">
111	                <label className="form-label">Product</label>
112	                <select
113	                  className="form-input"
114	                  value={form.productId}
115	                  onChange={(e) => setForm({ ...form, productId: e.target.value })}
116	                  required
117	                >
118	                  <option value="">Select a product</option>
119	                  {products.map((p) => (
120	                    <option key={p.id} value={p.id}>{p.name}</option>
121	                  ))}
122	                </select>
123	              </div>
124	              <div className="form-group">
125	                <label className="form-label">Title</label>
126	                <input
127	                  type="text"
128	                  className="form-input"
129	                  value={form.title}
130	                  onChange={(e) => handleTitleChange(e.target.value)}
131	                  required
132	                />
133	              </div>
134	              <div className="form-group">
135	                <label className="form-label">Slug</label>
136	                <input
137	                  type="text"
138	                  className="form-input"
