1	import React, { useEffect, useState } from 'react';
2	import { useAuthStore } from '@/state/authStore';
3	import { Incident } from '@/api/types';
4	import { getIncidents, getMyIncidents, createIncident } from '@/api/incidents';
5	
6	const TYPES = ['ORDER_ISSUE', 'PRODUCT_DEFECT', 'ACCOUNT_ISSUE', 'POLICY_VIOLATION', 'EMERGENCY', 'OTHER'];
7	const SEVERITIES = ['LOW', 'NORMAL', 'HIGH', 'EMERGENCY'];
8	
9	const severityBadge = (s: string) => {
10	  if (s === 'EMERGENCY' || s === 'HIGH') return 'badge badge-danger';
11	  if (s === 'NORMAL') return 'badge badge-warning';
12	  return 'badge badge-neutral';
13	};
14	
15	const statusBadge = (s: string) => {
16	  if (s === 'RESOLVED' || s === 'CLOSED') return 'badge badge-success';
17	  if (s === 'OPEN') return 'badge badge-danger';
18	  return 'badge badge-warning';
19	};
20	
21	const IncidentsPage: React.FC = () => {
22	  const user = useAuthStore((s) => s.user);
23	  const isMod = user?.role === 'MODERATOR' || user?.role === 'ADMINISTRATOR';
24	  const [incidents, setIncidents] = useState<Incident[]>([]);
25	  const [loading, setLoading] = useState(true);
26	  const [showForm, setShowForm] = useState(false);
27	  const [form, setForm] = useState({ incidentType: 'ORDER_ISSUE', severity: 'NORMAL', title: '', description: '', address: '', crossStreet: '' });
28	  const [error, setError] = useState('');
29	
30	  const load = async () => {
31	    setLoading(true);
32	    try {
33	      const data = isMod ? await getIncidents() : await getMyIncidents();
34	      setIncidents(data);
35	    } catch { setIncidents([]); }
36	    setLoading(false);
37	  };
38	
39	  useEffect(() => { load(); }, []);
40	
41	  const handleCreate = async (e: React.FormEvent) => {
42	    e.preventDefault();
43	    setError('');
44	    try {
45	      await createIncident({
46	        incidentType: form.incidentType,
47	        severity: form.severity,
48	        title: form.title,
49	        description: form.description,
50	        address: form.address || undefined,
51	        crossStreet: form.crossStreet || undefined,
52	      });
53	      setShowForm(false);
54	      setForm({ incidentType: 'ORDER_ISSUE', severity: 'NORMAL', title: '', description: '', address: '', crossStreet: '' });
55	      load();
56	    } catch (err: any) {
57	      setError(err.response?.data?.error || 'Failed to create incident');
58	    }
59	  };
60	
61	  const slaStatus = (incident: Incident) => {
62	    if (!incident.slaAckDeadline) return null;
63	    const deadline = new Date(incident.slaAckDeadline);
64	    const now = new Date();
65	    if (incident.status === 'OPEN' && deadline < now) return <span className="badge badge-danger">SLA BREACHED</span>;
66	    if (incident.status === 'OPEN') {
67	      const mins = Math.round((deadline.getTime() - now.getTime()) / 60000);
68	      return <span className="badge badge-warning">{mins}m to ack</span>;
69	    }
70	    return null;
71	  };
72	
73	  return (
74	    <div className="page">
75	      <div className="page-header">
76	        <h1>Incidents</h1>
77	        <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
78	          {showForm ? 'Cancel' : 'Report Incident'}
79	        </button>
80	      </div>
81	
82	      {showForm && (
83	        <div className="card" style={{ marginBottom: '1.5rem' }}>
84	          <div className="card-header">Report New Incident</div>
85	          <div className="card-body">
86	            {error && <div className="alert alert-danger">{error}</div>}
87	            <form onSubmit={handleCreate}>
88	              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
89	                <div className="form-group">
90	                  <label className="form-label">Type</label>
91	                  <select className="form-input" value={form.incidentType} onChange={(e) => setForm({ ...form, incidentType: e.target.value })}>
92	                    {TYPES.map((t) => <option key={t} value={t}>{t.replace(/_/g, ' ')}</option>)}
93	                  </select>
94	                </div>
95	                <div className="form-group">
96	                  <label className="form-label">Severity</label>
97	                  <select className="form-input" value={form.severity} onChange={(e) => setForm({ ...form, severity: e.target.value })}>
98	                    {SEVERITIES.map((s) => <option key={s} value={s}>{s}</option>)}
99	                  </select>
100	                </div>
101	              </div>
102	              <div className="form-group">
103	                <label className="form-label">Title</label>
104	                <input className="form-input" value={form.title} onChange={(e) => setForm({ ...form, title: e.target.value })} required />
105	              </div>
106	              <div className="form-group">
107	                <label className="form-label">Description</label>
108	                <textarea className="form-input" rows={4} value={form.description} onChange={(e) => setForm({ ...form, description: e.target.value })} required />
109	              </div>
110	              <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
111	                <div className="form-group">
112	                  <label className="form-label">Address (optional)</label>
113	                  <input className="form-input" placeholder="e.g. 123 Main St" value={form.address} onChange={(e) => setForm({ ...form, address: e.target.value })} />
114	                </div>
115	                <div className="form-group">
116	                  <label className="form-label">Cross Street (optional)</label>
117	                  <input className="form-input" placeholder="e.g. 5th Ave" value={form.crossStreet} onChange={(e) => setForm({ ...form, crossStreet: e.target.value })} />
118	                </div>
119	              </div>
120	              <div className="form-actions">
121	                <button type="submit" className="btn btn-primary">Submit Incident</button>
122	              </div>
123	            </form>
124	          </div>
125	        </div>
126	      )}
127	
128	      {loading ? (
129	        <p className="text-muted">Loading...</p>
130	      ) : incidents.length === 0 ? (
131	        <p className="text-muted">No incidents found.</p>
132	      ) : (
133	        <div className="table-wrapper">
134	          <table className="table">
135	            <thead>
136	              <tr>
137	                <th>ID</th><th>Title</th><th>Type</th><th>Severity</th><th>Status</th><th>SLA</th><th>Escalation</th><th>Created</th>
138	              </tr>
139	            </thead>
140	            <tbody>
141	              {incidents.map((inc) => (
142	                <tr key={inc.id} style={{ cursor: 'pointer' }} onClick={() => window.location.href = `/incidents/${inc.id}`}>
143	                  <td>#{inc.id}</td>
144	                  <td>{inc.title}</td>
145	                  <td>{inc.incidentType.replace(/_/g, ' ')}</td>
146	                  <td><span className={severityBadge(inc.severity)}>{inc.severity}</span></td>
147	                  <td><span className={statusBadge(inc.status)}>{inc.status}</span></td>
148	                  <td>{slaStatus(inc)}</td>
149	                  <td>{inc.escalationLevel > 0 ? <span className="badge badge-danger">L{inc.escalationLevel}</span> : '-'}</td>
150	                  <td>{new Date(inc.createdAt).toLocaleDateString()}</td>
151	                </tr>
152	              ))}
153	            </tbody>
154	          </table>
155	        </div>
156	      )}
157	    </div>
158	  );
159	};
160	
161	export default IncidentsPage;
162

