1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.exception.ResourceNotFoundException;
4	import com.demo.app.domain.model.Incident;
5	import com.demo.app.domain.model.IncidentComment;
6	import com.demo.app.persistence.entity.IncidentCommentEntity;
7	import com.demo.app.persistence.entity.IncidentEntity;
8	import com.demo.app.persistence.repository.IncidentCommentRepository;
9	import com.demo.app.persistence.repository.IncidentRepository;
10	import com.demo.app.persistence.repository.UserRepository;
11	import lombok.RequiredArgsConstructor;
12	import org.springframework.beans.factory.annotation.Value;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import com.demo.app.infrastructure.config.StatusTransitions;
17	
18	import java.time.LocalDateTime;
19	import java.util.List;
20	
21	@Service
22	@RequiredArgsConstructor
23	@Transactional
24	public class IncidentService {
25	
26	    private final IncidentRepository incidentRepository;
27	    private final IncidentCommentRepository incidentCommentRepository;
28	    private final UserRepository userRepository;
29	
30	    @Value("${app.incident.ack-sla-minutes:15}")
31	    private int ackSlaMinutes;
32	
33	    @Value("${app.incident.resolve-sla-hours:24}")
34	    private int resolveSlaHours;
35	
36	    private static final List<String> STATUS_ORDER = List.of(
37	            "OPEN", "ACKNOWLEDGED", "IN_PROGRESS", "RESOLVED", "CLOSED"
38	    );
39	
40	    public Incident create(Long reporterId, String incidentType, String severity, String title, String description,
41	                           String address, String crossStreet, Long sellerId) {
42	        LocalDateTime now = LocalDateTime.now();
43	
44	        int ackMinutes = ackSlaMinutes;
45	        int resolveHours = resolveSlaHours;
46	
47	        if ("EMERGENCY".equals(severity)) {
48	            ackMinutes = ackMinutes / 2;
49	            resolveHours = resolveHours / 2;
50	        }
51	
52	        if (sellerId != null && !userRepository.existsById(sellerId)) {
53	            throw new IllegalArgumentException("sellerId does not reference an existing user: " + sellerId);
54	        }
55	
56	        IncidentEntity entity = IncidentEntity.builder()
57	                .reporterId(reporterId)
58	                .sellerId(sellerId)
59	                .incidentType(incidentType)
60	                .severity(severity)
61	                .title(title)
62	                .description(description)
63	                .address(address)
64	                .crossStreet(crossStreet)
65	                .status("OPEN")
66	                .escalationLevel(0)
67	                .slaAckDeadline(now.plusMinutes(ackMinutes))
68	                .slaResolveDeadline(now.plusHours(resolveHours))
69	                .createdAt(now)
70	                .updatedAt(now)
71	                .build();
72	
73	        return incidentRepository.save(entity).toModel();
74	    }
75	
76	    public Incident acknowledge(Long incidentId, Long assigneeId) {
77	        IncidentEntity entity = incidentRepository.findById(incidentId)
78	                .orElseThrow(() -> new ResourceNotFoundException("Incident", incidentId));
79	
80	        int currentIndex = STATUS_ORDER.indexOf(entity.getStatus());
81	        int ackIndex = STATUS_ORDER.indexOf("ACKNOWLEDGED");
82	        if (currentIndex >= ackIndex) {
83	            return entity.toModel();
84	        }
85	
86	        LocalDateTime now = LocalDateTime.now();
87	        entity.setStatus("ACKNOWLEDGED");
88	        entity.setAssigneeId(assigneeId);
89	        entity.setAcknowledgedAt(now);
90	        entity.setUpdatedAt(now);
91	
92	        return incidentRepository.save(entity).toModel();
93	    }
94	
95	    public Incident updateStatus(Long incidentId, String newStatus, String closureCode) {
96	        IncidentEntity entity = incidentRepository.findById(incidentId)
97	                .orElseThrow(() -> new ResourceNotFoundException("Incident", incidentId));
98	
99	        StatusTransitions.validate(StatusTransitions.INCIDENT, entity.getStatus(), newStatus);
100	
101	        if ("RESOLVED".equals(newStatus) && (closureCode == null || closureCode.isBlank())) {
102	            throw new IllegalArgumentException("Closure code is required when resolving an incident");
103	        }
104	
105	        LocalDateTime now = LocalDateTime.now();
106	        entity.setStatus(newStatus);
107	        entity.setUpdatedAt(now);
108	
109	        if ("RESOLVED".equals(newStatus)) {
110	            entity.setResolvedAt(now);
111	            entity.setClosureCode(closureCode);
112	        }
113	
114	        return incidentRepository.save(entity).toModel();
115	    }
116	
117	    public IncidentComment addComment(Long incidentId, Long authorId, String content) {
118	        IncidentCommentEntity entity = IncidentCommentEntity.builder()
119	                .incidentId(incidentId)
120	                .authorId(authorId)
121	                .content(content)
122	                .createdAt(LocalDateTime.now())
123	                .build();
124	
125	        return incidentCommentRepository.save(entity).toModel();
126	    }
127	
128	    @Transactional(readOnly = true)
129	    public Incident getById(Long id) {
130	        return incidentRepository.findById(id)
131	                .orElseThrow(() -> new ResourceNotFoundException("Incident", id))
132	                .toModel();
133	    }
134	
135	    @Transactional(readOnly = true)
136	    public List<Incident> getByReporter(Long reporterId) {
137	        return incidentRepository.findByReporterId(reporterId).stream()
138	                .map(IncidentEntity::toModel)
139	                .toList();
140	    }
141	
142	    @Transactional(readOnly = true)
143	    public List<Incident> getAll() {
144	        return incidentRepository.findAll().stream()
145	                .map(IncidentEntity::toModel)
146	                .toList();
147	    }
148	
149	    @Transactional(readOnly = true)
150	    public List<IncidentComment> getComments(Long incidentId) {
151	        return incidentCommentRepository.findByIncidentIdOrderByCreatedAtAsc(incidentId).stream()
152	                .map(IncidentCommentEntity::toModel)
153	                .toList();
154	    }
155	}
