1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.exception.OwnershipViolationException;
4	import com.demo.app.domain.model.BenefitItem;
5	import com.demo.app.domain.model.BenefitPackage;
6	import com.demo.app.persistence.entity.BenefitItemEntity;
7	import com.demo.app.persistence.entity.BenefitIssuanceLedgerEntity;
8	import com.demo.app.persistence.entity.BenefitRedemptionLedgerEntity;
9	import com.demo.app.persistence.entity.IncidentEntity;
10	import com.demo.app.persistence.entity.OrderEntity;
11	import com.demo.app.domain.exception.ResourceNotFoundException;
12	import com.demo.app.persistence.repository.BenefitIssuanceLedgerRepository;
13	import com.demo.app.persistence.repository.BenefitItemRepository;
14	import com.demo.app.persistence.repository.BenefitPackageRepository;
15	import com.demo.app.persistence.repository.BenefitRedemptionLedgerRepository;
16	import com.demo.app.persistence.repository.OrderRepository;
17	import com.demo.app.persistence.repository.IncidentRepository;
18	import lombok.RequiredArgsConstructor;
19	import org.springframework.stereotype.Service;
20	
21	import java.time.LocalDateTime;
22	import java.util.List;
23	
24	@Service
25	@RequiredArgsConstructor
26	public class BenefitService {
27	
28	    private final BenefitPackageRepository benefitPackageRepository;
29	    private final BenefitItemRepository benefitItemRepository;
30	    private final BenefitIssuanceLedgerRepository benefitIssuanceLedgerRepository;
31	    private final BenefitRedemptionLedgerRepository benefitRedemptionLedgerRepository;
32	    private final OrderRepository orderRepository;
33	    private final IncidentRepository incidentRepository;
34	
35	    public List<BenefitPackage> getPackagesByTier(Long tierId) {
36	        return benefitPackageRepository.findByTierIdAndActiveTrue(tierId).stream()
37	                .map(e -> e.toModel())
38	                .toList();
39	    }
40	
41	    public List<BenefitItem> getItemsByPackage(Long packageId) {
42	        return benefitItemRepository.findByPackageId(packageId).stream()
43	                .map(e -> e.toModel())
44	                .toList();
45	    }
46	
47	    public BenefitIssuanceLedgerEntity issueBenefit(Long memberId, Long benefitItemId, Long issuedByUserId, String reference, String referenceType, Long referenceId) {
48	        if (referenceType == null || referenceType.isBlank()) {
49	            throw new IllegalArgumentException("referenceType is required. Must be ORDER or INCIDENT.");
50	        }
51	
52	        Long orderId = null;
53	        Long incidentId = null;
54	
55	        if ("ORDER".equals(referenceType)) {
56	                if (referenceId == null || !orderRepository.existsById(referenceId)) {
57	                    throw new ResourceNotFoundException("Order", referenceId);
58	                }
59	                orderId = referenceId;
60	            } else if ("INCIDENT".equals(referenceType)) {
61	                if (referenceId == null || !incidentRepository.existsById(referenceId)) {
62	                    throw new ResourceNotFoundException("Incident", referenceId);
63	                }
64	                incidentId = referenceId;
65	            } else {
66	            throw new IllegalArgumentException("Invalid referenceType: " + referenceType + ". Must be ORDER or INCIDENT.");
67	        }
68	
69	        BenefitIssuanceLedgerEntity entity = BenefitIssuanceLedgerEntity.builder()
70	                .memberId(memberId)
71	                .benefitItemId(benefitItemId)
72	                .issuedBy(issuedByUserId)
73	                .reference(reference)
74	                .referenceType(referenceType)
75	                .referenceId(referenceId)
76	                .orderId(orderId)
77	                .incidentId(incidentId)
78	                .issuedAt(LocalDateTime.now())
79	                .build();
80	        return benefitIssuanceLedgerRepository.save(entity);
81	    }
82	
83	    public BenefitRedemptionLedgerEntity redeemBenefit(Long callerUserId, Long memberId, Long benefitItemId, String reference, Long orderCategoryId, Long orderSellerId, String referenceType, Long referenceId) {
84	        if (callerUserId == null) {
85	            throw new IllegalArgumentException("callerUserId is required for redemption (no anonymous redeem)");
86	        }
87	        BenefitItemEntity item = benefitItemRepository.findById(benefitItemId)
88	                .orElseThrow(() -> new com.demo.app.domain.exception.ResourceNotFoundException("Benefit item", benefitItemId));
89	
90	        // Check mutual exclusion: if this item has an exclusion group, verify no other
91	        // item from the same group has been redeemed with the same reference (transaction)
92	        if (item.getExclusionGroup() != null && reference != null) {
93	            List<BenefitRedemptionLedgerEntity> existing = benefitRedemptionLedgerRepository.findByMemberId(memberId);
94	            boolean conflict = existing.stream().anyMatch(r ->
95	                    reference.equals(r.getReference()) && benefitItemRepository.findById(r.getBenefitItemId())
96	                            .map(bi -> item.getExclusionGroup().equals(bi.getExclusionGroup()) && !bi.getId().equals(item.getId()))
97	                            .orElse(false));
98	            if (conflict) {
99	                throw new com.demo.app.domain.exception.ConflictException(
100	                        "Cannot redeem: another benefit in exclusion group '" + item.getExclusionGroup() + "' is already applied to this transaction");
101	            }
102	        }
103	
104	        // Enforce date window
105	        LocalDateTime now = LocalDateTime.now();
106	        if (item.getValidFrom() != null && now.isBefore(item.getValidFrom())) {
107	            throw new com.demo.app.domain.exception.ConflictException("Benefit not yet active. Valid from: " + item.getValidFrom());
108	        }
109	        if (item.getValidTo() != null && now.isAfter(item.getValidTo())) {
110	            throw new com.demo.app.domain.exception.ConflictException("Benefit has expired. Valid until: " + item.getValidTo());
111	        }
112	
113	        // Enforce category scope
114	        if (item.getCategoryId() != null && orderCategoryId != null
115	                && !item.getCategoryId().equals(orderCategoryId)) {
116	            throw new com.demo.app.domain.exception.ConflictException(
117	                    "Benefit is restricted to category " + item.getCategoryId() + " but order is category " + orderCategoryId);
118	        }
119	
120	        // Enforce seller scope
121	        if (item.getSellerId() != null && orderSellerId != null
122	                && !item.getSellerId().equals(orderSellerId)) {
123	            throw new com.demo.app.domain.exception.ConflictException(
124	                    "Benefit is restricted to seller " + item.getSellerId() + " but order is from seller " + orderSellerId);
125	        }
126	
127	        if (referenceType == null || referenceType.isBlank()) {
128	            throw new IllegalArgumentException("referenceType is required. Must be ORDER or INCIDENT.");
129	        }
130	
131	        Long orderId = null;
132	        Long incidentId = null;
133	
134	        // Strict object-level authorization: a caller can only redeem against an
135	        // order they bought or an incident they reported. Without this check a
136	        // member could pass any orderId/incidentId in the request body and earn
137	        // benefits tied to other users' transactions.
138	        if ("ORDER".equals(referenceType)) {
139	            if (referenceId == null) {
140	                throw new ResourceNotFoundException("Order", referenceId);
141	            }
