1	package com.demo.app.application.service;
2	
3	import com.demo.app.domain.model.InventoryItem;
4	import com.demo.app.persistence.entity.InventoryItemEntity;
5	import com.demo.app.persistence.entity.InventoryMovementEntity;
6	import com.demo.app.persistence.repository.InventoryItemRepository;
7	import com.demo.app.persistence.repository.InventoryMovementRepository;
8	import lombok.RequiredArgsConstructor;
9	import lombok.extern.slf4j.Slf4j;
10	import org.springframework.stereotype.Service;
11	import org.springframework.transaction.annotation.Transactional;
12	
13	import java.time.LocalDateTime;
14	import java.util.List;
15	
16	@Service
17	@RequiredArgsConstructor
18	@Transactional
19	@Slf4j
20	public class InventoryService {
21	
22	    private final InventoryItemRepository inventoryItemRepository;
23	    private final InventoryMovementRepository inventoryMovementRepository;
24	
25	    public InventoryItem getByProductAndWarehouse(Long productId, Long warehouseId) {
26	        return inventoryItemRepository.findByProductIdAndWarehouseId(productId, warehouseId)
27	                .orElseThrow(() -> new RuntimeException("Inventory item not found for product " + productId + " and warehouse " + warehouseId))
28	                .toModel();
29	    }
30	
31	    public List<InventoryItem> getByProduct(Long productId) {
32	        return inventoryItemRepository.findByProductId(productId).stream()
33	                .map(InventoryItemEntity::toModel)
34	                .toList();
35	    }
36	
37	    public List<InventoryItem> getLowStockItems() {
38	        return inventoryItemRepository.findLowStock().stream()
39	                .map(InventoryItemEntity::toModel)
40	                .toList();
41	    }
42	
43	    public InventoryItem adjustStock(Long inventoryItemId, int quantityChange, String movementType,
44	                                     String referenceDocument, Long operatorId, String notes) {
45	        InventoryItemEntity item = inventoryItemRepository.findById(inventoryItemId)
46	                .orElseThrow(() -> new RuntimeException("Inventory item not found: " + inventoryItemId));
47	
48	        int newQuantityOnHand = item.getQuantityOnHand() + quantityChange;
49	        if (newQuantityOnHand < 0) {
50	            throw new RuntimeException("Insufficient stock. Current on-hand: " + item.getQuantityOnHand()
51	                    + ", requested change: " + quantityChange);
52	        }
53	
54	        item.setQuantityOnHand(newQuantityOnHand);
55	        item.setUpdatedAt(LocalDateTime.now());
56	        inventoryItemRepository.save(item);
57	
58	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
59	                .inventoryItemId(inventoryItemId)
60	                .warehouseId(item.getWarehouseId())
61	                .movementType(movementType)
62	                .quantity(quantityChange)
63	                .balanceAfter(newQuantityOnHand)
64	                .referenceDocument(referenceDocument)
65	                .operatorId(operatorId)
66	                .notes(notes)
67	                .createdAt(LocalDateTime.now())
68	                .build();
69	        inventoryMovementRepository.save(movement);
70	
71	        int available = newQuantityOnHand - item.getQuantityReserved();
72	        // Strict < 5 system-wide low-stock alert, or per-item threshold if higher
73	        int effectiveThreshold = Math.max(5, item.getLowStockThreshold());
74	        if (available < effectiveThreshold) {
75	            log.warn("LOW STOCK ALERT: item {} available={} below threshold={} (system minimum=5)",
76	                    inventoryItemId, available, effectiveThreshold);
77	        }
78	
79	        return item.toModel();
80	    }
81	}
