3	import com.demo.app.domain.enums.OrderStatus;
4	import com.demo.app.domain.exception.ResourceNotFoundException;
5	import com.demo.app.domain.model.Order;
6	import com.demo.app.persistence.entity.OrderEntity;
7	import com.demo.app.persistence.entity.ProductEntity;
8	import com.demo.app.persistence.entity.UserEntity;
9	import com.demo.app.persistence.repository.OrderRepository;
10	import com.demo.app.persistence.repository.ProductRepository;
11	import com.demo.app.persistence.repository.UserRepository;
12	import lombok.RequiredArgsConstructor;
13	import org.springframework.stereotype.Service;
14	import org.springframework.transaction.annotation.Transactional;
15	
16	import java.time.LocalDateTime;
17	import java.util.List;
18	import java.util.Map;
19	import java.util.Set;
20	
21	@Service
22	@RequiredArgsConstructor
23	public class OrderService {
24	
25	    private final OrderRepository orderRepository;
26	    private final UserRepository userRepository;
27	    private final ProductRepository productRepository;
28	
29	    private static final Map<String, Set<String>> ORDER_TRANSITIONS = Map.of(
30	            "PLACED", Set.of("CONFIRMED", "CANCELLED"),
31	            "CONFIRMED", Set.of("SHIPPED", "CANCELLED"),
32	            "SHIPPED", Set.of("DELIVERED"),
33	            "DELIVERED", Set.of(),
34	            "CANCELLED", Set.of()
35	    );
36	
37	    @Transactional(readOnly = true)
38	    public List<Order> getAll() {
39	        return orderRepository.findAll().stream()
40	                .map(OrderEntity::toModel)
41	                .toList();
42	    }
43	
44	    @Transactional(readOnly = true)
45	    public Order getById(Long id) {
46	        return orderRepository.findById(id)
47	                .map(OrderEntity::toModel)
48	                .orElseThrow(() -> new ResourceNotFoundException("Order", id));
49	    }
50	
51	    @Transactional(readOnly = true)
52	    public List<Order> getByBuyer(Long buyerId) {
53	        return orderRepository.findByBuyer_Id(buyerId).stream()
54	                .map(OrderEntity::toModel)
55	                .toList();
56	    }
57	
58	    @Transactional
59	    public Order placeOrder(Order order) {
60	        UserEntity buyer = userRepository.findById(order.getBuyerId())
61	                .orElseThrow(() -> new RuntimeException("Buyer not found with id: " + order.getBuyerId()));
62	        ProductEntity product = productRepository.findById(order.getProductId())
63	                .orElseThrow(() -> new RuntimeException("Product not found with id: " + order.getProductId()));
64	
65	        OrderEntity entity = OrderEntity.builder()
66	                .buyer(buyer)
67	                .product(product)
68	                .quantity(order.getQuantity())
69	                .totalPrice(order.getTotalPrice())
70	                .status(OrderStatus.PLACED)
71	                .createdAt(LocalDateTime.now())
72	                .updatedAt(LocalDateTime.now())
73	                .build();
74	        return orderRepository.save(entity).toModel();
75	    }
76	
77	    @Transactional
78	    public Order updateStatus(Long id, OrderStatus newStatus) {
79	        OrderEntity entity = orderRepository.findById(id)
80	                .orElseThrow(() -> new ResourceNotFoundException("Order", id));
81	
82	        String current = entity.getStatus().name();
83	        String target = newStatus.name();
84	
85	        // Idempotent: if already at target status, return as-is
86	        if (current.equals(target)) {
87	            return entity.toModel();
88	        }
89	
90	        Set<String> allowed = ORDER_TRANSITIONS.get(current);
91	        if (allowed == null || !allowed.contains(target)) {
92	            throw new IllegalStateException("Invalid order transition from " + current + " to " + target);
93	        }
94	
95	        entity.setStatus(newStatus);
96	        entity.setUpdatedAt(LocalDateTime.now());
97	        return orderRepository.save(entity).toModel();
98	    }
99	}
