14	import org.springframework.web.bind.annotation.*;
15	
16	import java.util.List;
17	
18	@RestController
19	@RequestMapping("/api/orders")
20	@RequiredArgsConstructor
21	public class OrderController {
22	
23	    private final OrderService orderService;
24	    private final UserRepository userRepository;
25	
26	    @GetMapping
27	    @PreAuthorize("hasAnyRole('WAREHOUSE_STAFF', 'MODERATOR', 'ADMINISTRATOR')")
28	    public ResponseEntity<List<OrderDto>> getAll() {
29	        List<OrderDto> orders = orderService.getAll().stream()
30	                .map(this::toDto)
31	                .toList();
32	        return ResponseEntity.ok(orders);
33	    }
34	
35	    @GetMapping("/{id}")
36	    public ResponseEntity<OrderDto> getById(@PathVariable Long id) {
37	        Order order = orderService.getById(id);
38	        enforceOwnership(order.getBuyerId());
39	        return ResponseEntity.ok(toDto(order));
40	    }
41	
42	    @GetMapping("/buyer/{buyerId}")
43	    public ResponseEntity<List<OrderDto>> getByBuyer(@PathVariable Long buyerId) {
44	        enforceOwnership(buyerId);
45	        List<OrderDto> orders = orderService.getByBuyer(buyerId).stream()
46	                .map(this::toDto)
47	                .toList();
48	        return ResponseEntity.ok(orders);
49	    }
50	
51	    @PostMapping
52	    @Audited(entityType = "ORDER", action = "PLACE")
53	    public ResponseEntity<OrderDto> placeOrder(@RequestBody OrderDto dto) {
54	        Long authenticatedUserId = getCurrentUserId();
55	        Order order = Order.builder()
56	                .buyerId(authenticatedUserId)
57	                .productId(dto.productId())
58	                .quantity(dto.quantity())
59	                .totalPrice(dto.totalPrice())
60	                .build();
61	        return ResponseEntity.ok(toDto(orderService.placeOrder(order)));
62	    }
63	
64	    @PatchMapping("/{id}/status")
65	    @Audited(entityType = "ORDER", action = "STATUS_CHANGE")
66	    public ResponseEntity<OrderDto> updateStatus(@PathVariable Long id, @RequestParam OrderStatus status) {
67	        Order order = orderService.getById(id);
68	
69	        // Buyers can only cancel their own orders
70	        if (!isPrivileged()) {
71	            enforceOwnership(order.getBuyerId());
72	            if (status != OrderStatus.CANCELLED) {
73	                throw new OwnershipViolationException("Buyers can only cancel orders. Status changes to " + status + " require staff privileges.");
74	            }
75	        }
76	
77	        return ResponseEntity.ok(toDto(orderService.updateStatus(id, status)));
78	    }
