80	    private void enforceOwnership(Long ownerId) {
81	        if (isPrivileged()) return;
82	        Long currentUserId = getCurrentUserId();
83	        if (!currentUserId.equals(ownerId)) {
84	            throw new OwnershipViolationException("You do not have access to this resource");
85	        }
86	    }
87	
88	    private boolean isPrivileged() {
89	        var auth = SecurityContextHolder.getContext().getAuthentication();
90	        return auth.getAuthorities().stream().anyMatch(a ->
91	                a.getAuthority().equals("ROLE_ADMINISTRATOR") ||
92	                a.getAuthority().equals("ROLE_MODERATOR") ||
93	                a.getAuthority().equals("ROLE_WAREHOUSE_STAFF"));
94	    }
