96	    private Long getCurrentUserId() {
97	        String username = SecurityContextHolder.getContext().getAuthentication().getName();
98	        return userRepository.findByUsername(username)
99	                .orElseThrow(() -> new RuntimeException("User not found"))
100	                .getId();
101	    }
