137	    @Transactional(readOnly = true)
138	    public List<Listing> searchAdvanced(String query, String neighborhood,
139	                                         Double userLat, Double userLng, Double radiusMiles,
140	                                         java.time.LocalDate availableAfter,
141	                                         java.time.LocalDate availableBefore,
142	                                         java.math.BigDecimal minPrice, java.math.BigDecimal maxPrice,
143	                                         Integer minSqft, Integer maxSqft,
144	                                         String layout) {
145	        List<ListingEntity> all = listingRepository.findByStatus("PUBLISHED");
146	
147	        return all.stream()
148	                .filter(l -> query == null || query.isBlank()
149	                        || l.getTitle().toLowerCase().contains(query.toLowerCase())
150	                        || (l.getSummary() != null && l.getSummary().toLowerCase().contains(query.toLowerCase())))
151	                .filter(l -> neighborhood == null || neighborhood.isBlank()
152	                        || (l.getNeighborhood() != null && l.getNeighborhood().equalsIgnoreCase(neighborhood)))
153	                .filter(l -> availableAfter == null
154	                        || (l.getAvailableFrom() != null && !l.getAvailableFrom().isAfter(availableAfter)))
155	                .filter(l -> availableBefore == null
156	                        || (l.getAvailableTo() != null && !l.getAvailableTo().isBefore(availableBefore)))
157	                .filter(l -> minPrice == null
158	                        || (l.getPrice() != null && l.getPrice().compareTo(minPrice) >= 0))
159	                .filter(l -> maxPrice == null
160	                        || (l.getPrice() != null && l.getPrice().compareTo(maxPrice) <= 0))
161	                .filter(l -> minSqft == null
162	                        || (l.getSqft() != null && l.getSqft() >= minSqft))
163	                .filter(l -> maxSqft == null
164	                        || (l.getSqft() != null && l.getSqft() <= maxSqft))
165	                .filter(l -> layout == null || layout.isBlank()
166	                        || (l.getLayout() != null && l.getLayout().equalsIgnoreCase(layout)))
167	                .filter(l -> {
168	                    if (radiusMiles == null || userLat == null || userLng == null) return true;
169	                    if (l.getLatitude() == null || l.getLongitude() == null) return false;
170	                    double distKm = haversine(userLat, userLng, l.getLatitude(), l.getLongitude());
171	                    double distMiles = distKm / 1.609344;
172	                    return distMiles <= radiusMiles;
173	                })
174	                .sorted((a, b) -> {
175	                    if (userLat != null && userLng != null
176	                            && a.getLatitude() != null && a.getLongitude() != null
177	                            && b.getLatitude() != null && b.getLongitude() != null) {
178	                        double distA = haversine(userLat, userLng, a.getLatitude(), a.getLongitude());
179	                        double distB = haversine(userLat, userLng, b.getLatitude(), b.getLongitude());
180	                        return Double.compare(distA, distB);
181	                    }
182	                    return Double.compare(b.getSearchRank(), a.getSearchRank());
183	                })
184	                .map(ListingEntity::toModel)
185	                .toList();
186	    }
