188	    @Transactional
189	    public void refreshWeeklyViews() {
190	        // Decay weekly views by 15% daily to approximate a rolling 7-day window
191	        listingRepository.findAll().forEach(listing -> {
192	            long decayed = (long) (listing.getWeeklyViews() * 0.85);
193	            listing.setWeeklyViews(decayed);
194	            listing.setUpdatedAt(java.time.LocalDateTime.now());
195	            listingRepository.save(listing);
196	        });
197	    }
198	
199	    private double haversine(double lat1, double lon1, double lat2, double lon2) {
200	        double R = 6371.0; // km
201	        double dLat = Math.toRadians(lat2 - lat1);
202	        double dLon = Math.toRadians(lon2 - lon1);
203	        double a = Math.sin(dLat / 2) * Math.sin(dLat / 2)
204	                + Math.cos(Math.toRadians(lat1)) * Math.cos(Math.toRadians(lat2))
205	                * Math.sin(dLon / 2) * Math.sin(dLon / 2);
206	        return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
207	    }
208	}
