94	    public StockReservation confirm(Long reservationId) {
95	        StockReservationEntity reservation = stockReservationRepository.findById(reservationId)
96	                .orElseThrow(() -> new ResourceNotFoundException("Reservation", reservationId));
97	
98	        if (ReservationStatus.CONFIRMED.name().equals(reservation.getStatus())) {
99	            return reservation.toModel();
100	        }
101	
102	        if (!ReservationStatus.HELD.name().equals(reservation.getStatus())) {
103	            throw new IllegalStateException("Reservation cannot be confirmed. Current status: " + reservation.getStatus());
104	        }
105	
106	        LocalDateTime now = LocalDateTime.now();
107	        reservation.setStatus(ReservationStatus.CONFIRMED.name());
108	        reservation.setConfirmedAt(now);
109	        stockReservationRepository.save(reservation);
110	
111	        InventoryItemEntity item = inventoryItemRepository.findById(reservation.getInventoryItemId())
112	                .orElseThrow(() -> new ResourceNotFoundException("Inventory item", reservation.getInventoryItemId()));
113	
114	        item.setQuantityOnHand(item.getQuantityOnHand() - reservation.getQuantity());
115	        item.setQuantityReserved(item.getQuantityReserved() - reservation.getQuantity());
116	        item.setUpdatedAt(now);
117	        inventoryItemRepository.save(item);
118	
119	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
120	                .inventoryItemId(item.getId())
121	                .warehouseId(item.getWarehouseId())
122	                .movementType(MovementType.SHIPMENT.name())
123	                .quantity(-reservation.getQuantity())
124	                .balanceAfter(item.getQuantityOnHand())
125	                .referenceDocument("reservation:" + reservationId)
126	                .operatorId(reservation.getUserId())
127	                .createdAt(now)
128	                .build();
129	        inventoryMovementRepository.save(movement);
130	
131	        return reservation.toModel();
132	    }
