134	    public StockReservation cancel(Long reservationId) {
135	        StockReservationEntity reservation = stockReservationRepository.findById(reservationId)
136	                .orElseThrow(() -> new ResourceNotFoundException("Reservation", reservationId));
137	
138	        if (ReservationStatus.CANCELLED.name().equals(reservation.getStatus())
139	                || ReservationStatus.EXPIRED.name().equals(reservation.getStatus())) {
140	            return reservation.toModel();
141	        }
142	
143	        if (!ReservationStatus.HELD.name().equals(reservation.getStatus())) {
144	            throw new IllegalStateException("Reservation cannot be cancelled. Current status: " + reservation.getStatus());
145	        }
146	
147	        LocalDateTime now = LocalDateTime.now();
148	        reservation.setStatus(ReservationStatus.CANCELLED.name());
149	        reservation.setCancelledAt(now);
150	        stockReservationRepository.save(reservation);
151	
152	        InventoryItemEntity item = inventoryItemRepository.findById(reservation.getInventoryItemId())
153	                .orElseThrow(() -> new ResourceNotFoundException("Inventory item", reservation.getInventoryItemId()));
154	
155	        item.setQuantityReserved(item.getQuantityReserved() - reservation.getQuantity());
156	        item.setUpdatedAt(now);
157	        inventoryItemRepository.save(item);
158	
159	        InventoryMovementEntity movement = InventoryMovementEntity.builder()
160	                .inventoryItemId(item.getId())
161	                .warehouseId(item.getWarehouseId())
162	                .movementType(MovementType.RESERVATION_RELEASE.name())
163	                .quantity(reservation.getQuantity())
164	                .balanceAfter(item.getQuantityOnHand())
165	                .referenceDocument("reservation:" + reservationId)
166	                .operatorId(reservation.getUserId())
167	                .createdAt(now)
168	                .build();
169	        inventoryMovementRepository.save(movement);
170	
171	        return reservation.toModel();
172	    }
