                            return Double.compare(distA, distB);
                        }
                        return Double.compare(b.getSearchRank(), a.getSearchRank());
                    });
        };

        return filtered
                .sorted(comparator)
                .map(ListingEntity::toModel)
                .toList();
    }"}

